type PreparationModeInputProps = {
  value: string
  onChange: (value: string) => void
  placeholder: string
  ingredientNames: string[]
}

function isPreparationModeBoundary(character: string | undefined) {
  return !character || !/[A-Z0-9]/.test(character)
}

function normalizePreparationModeIngredientNames(ingredientNames: string[]) {
  return Array.from(new Set(ingredientNames.map((name) => name.trim()).filter(Boolean))).sort(
    (left, right) => right.length - left.length || left.localeCompare(right),
  )
}

function normalizeFreeText(value: string) {
  const normalized = value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^A-Za-z0-9 .,;:!?()/%"'_\n-]/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\s*\n\s*/g, '\n')
    .trimStart()

  return normalized.toUpperCase()
}

function normalizePreparationModeEditingValue(value: string) {
  return value.toLocaleUpperCase('pt-BR')
}

function normalizePreparationModeComparableValue(value: string) {
  return value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLocaleUpperCase('pt-BR')
}

function getPreparationModeNameMatchIndex(name: string, query: string) {
  if (!query) {
    return -1
  }

  if (name.startsWith(query)) {
    return 0
  }

  const paddedName = ` ${name}`
  const paddedQuery = ` ${query}`
  const matchIndex = paddedName.indexOf(paddedQuery)
  return matchIndex === -1 ? -1 : matchIndex - 1
}

function getPreparationModeAutocomplete(
  value: string,
  caretIndex: number,
  ingredientNames: string[],
) {
  const textBeforeCaret = value.slice(0, caretIndex)
  const segmentStart = Math.max(
    textBeforeCaret.lastIndexOf('\n'),
    textBeforeCaret.lastIndexOf('.'),
    textBeforeCaret.lastIndexOf(','),
    textBeforeCaret.lastIndexOf(';'),
    textBeforeCaret.lastIndexOf(':'),
    textBeforeCaret.lastIndexOf('!'),
    textBeforeCaret.lastIndexOf('?'),
    textBeforeCaret.lastIndexOf('('),
    textBeforeCaret.lastIndexOf(')'),
  ) + 1
  const segment = textBeforeCaret.slice(segmentStart)
  const trimmedSegment = segment.trimStart()
  const leadingWhitespaceLength = segment.length - trimmedSegment.length
  const trimmedSegmentStart = segmentStart + leadingWhitespaceLength
  const queryCandidates = Array.from(
    new Set(
      trimmedSegment
        .split(/\s+/)
        .map((_, index, words) => words.slice(index).join(' ').trim())
        .filter(Boolean),
    ),
  )

  if (queryCandidates.length === 0) {
    return null
  }

  for (const query of queryCandidates) {
    const normalizedQuery = normalizePreparationModeComparableValue(query)
    if (!normalizedQuery) {
      continue
    }

    const suggestions = ingredientNames
      .map((name) => {
        const normalizedName = normalizePreparationModeComparableValue(name)
        return {
          name,
          normalizedName,
          matchIndex: getPreparationModeNameMatchIndex(normalizedName, normalizedQuery),
        }
      })
      .filter(({ normalizedName, matchIndex }) => matchIndex !== -1 && normalizedName !== normalizedQuery)
      .sort(
        (left, right) =>
          left.matchIndex - right.matchIndex ||
          left.normalizedName.length - right.normalizedName.length ||
          left.name.localeCompare(right.name),
      )
      .slice(0, 5)
      .map(({ name }) => name)

    if (suggestions.length === 0) {
      continue
    }

    const queryStartInTrimmedSegment = trimmedSegment.lastIndexOf(query)
    return {
      start: trimmedSegmentStart + queryStartInTrimmedSegment,
      suggestions,
    }
  }

  return null
}

function buildPreparationModeHighlightParts(value: string, ingredientNames: string[]) {
  if (!value) {
    return [{ text: '', isMatch: false }]
  }

  const matches: Array<{ start: number; end: number }> = []
  let cursor = 0

  while (cursor < value.length) {
    const matchedName = ingredientNames.find((name) => {
      const candidate = value.slice(cursor, cursor + name.length)
      if (normalizePreparationModeComparableValue(candidate) !== normalizePreparationModeComparableValue(name)) {
        return false
      }

      const characterBefore = cursor > 0 ? value[cursor - 1] : undefined
      const characterAfter = value[cursor + name.length]
      return isPreparationModeBoundary(characterBefore) && isPreparationModeBoundary(characterAfter)
    })

    if (matchedName) {
      matches.push({ start: cursor, end: cursor + matchedName.length })
      cursor += matchedName.length
      continue
    }

    cursor += 1
  }

  if (matches.length === 0) {
    return [{ text: value, isMatch: false }]
  }

  const parts: Array<{ text: string; isMatch: boolean }> = []
  let lastIndex = 0

  matches.forEach((match) => {
    if (match.start > lastIndex) {
      parts.push({ text: value.slice(lastIndex, match.start), isMatch: false })
    }
    parts.push({ text: value.slice(match.start, match.end), isMatch: true })
    lastIndex = match.end
  })

  if (lastIndex < value.length) {
    parts.push({ text: value.slice(lastIndex), isMatch: false })
  }

  return parts
}

function buildPreparationModeMetricParts(value: string, ingredients: RecipePanelIngredientMetrics[]): PreparationModeMetricPart[] {
  if (!value) {
    return [{ type: 'text', text: '' }]
  }

  const sortedIngredients = [...ingredients]
    .filter((ingredient) => ingredient.label.trim() !== '')
    .sort((left, right) => right.label.length - left.label.length || left.label.localeCompare(right.label))

  const parts: PreparationModeMetricPart[] = []
  let cursor = 0
  let lastIndex = 0

  while (cursor < value.length) {
    const matchedIngredient = sortedIngredients.find((ingredient) => {
      const candidate = value.slice(cursor, cursor + ingredient.label.length)
      if (
        normalizePreparationModeComparableValue(candidate) !==
        normalizePreparationModeComparableValue(ingredient.label)
      ) {
        return false
      }

      const characterBefore = cursor > 0 ? value[cursor - 1] : undefined
      const characterAfter = value[cursor + ingredient.label.length]
      return isPreparationModeBoundary(characterBefore) && isPreparationModeBoundary(characterAfter)
    })

    if (!matchedIngredient) {
      cursor += 1
      continue
    }

    if (cursor > lastIndex) {
      parts.push({ type: 'text', text: value.slice(lastIndex, cursor) })
    }

    parts.push({
      type: 'ingredient',
      text: value.slice(cursor, cursor + matchedIngredient.label.length),
      quantityLabel: `${formatDecimal(matchedIngredient.scaledInputQuantity)} ${matchedIngredient.unitLabel}`,
    })
    cursor += matchedIngredient.label.length
    lastIndex = cursor
  }

  if (lastIndex < value.length) {
    parts.push({ type: 'text', text: value.slice(lastIndex) })
  }

  return parts.length > 0 ? parts : [{ type: 'text', text: value }]
}

function PreparationModeInput({
  value,
  onChange,
  placeholder,
  ingredientNames,
}: PreparationModeInputProps) {
  const textareaId = useId()
  const [caretIndex, setCaretIndex] = useState(value.length)
  const normalizedIngredientNames = useMemo(
    () => normalizePreparationModeIngredientNames(ingredientNames),
    [ingredientNames],
  )
  const autocomplete = useMemo(
    () => getPreparationModeAutocomplete(value, caretIndex, normalizedIngredientNames),
    [caretIndex, normalizedIngredientNames, value],
  )

  function applySuggestion(suggestion: string) {
    if (!autocomplete) {
      return
    }

    const nextValue = `${value.slice(0, autocomplete.start)}${suggestion}${value.slice(caretIndex)}`
    const nextCaretIndex = autocomplete.start + suggestion.length
    onChange(nextValue)
    setCaretIndex(nextCaretIndex)

    requestAnimationFrame(() => {
      const textarea = document.getElementById(textareaId) as HTMLTextAreaElement | null
      if (!textarea) {
        return
      }

      textarea.focus()
      textarea.setSelectionRange(nextCaretIndex, nextCaretIndex)
    })
  }

  return (
    <div className="recipe-textarea-field">
      <Editor
        value={value}
        onValueChange={(nextValue) => {
          const textarea = document.getElementById(textareaId) as HTMLTextAreaElement | null
          const nextCaretIndex = textarea?.selectionStart ?? caretIndex
          const normalizedValue = normalizePreparationModeEditingValue(nextValue)
          onChange(normalizedValue)
          setCaretIndex(nextCaretIndex)

          if (normalizedValue !== nextValue) {
            requestAnimationFrame(() => {
              const nextTextarea = document.getElementById(textareaId) as HTMLTextAreaElement | null
              if (!nextTextarea) {
                return
              }

              nextTextarea.setSelectionRange(nextCaretIndex, nextCaretIndex)
            })
          }
        }}
        highlight={(code) => (
          <>
            {code ? (
              <>
                {buildPreparationModeHighlightParts(code, normalizedIngredientNames).map((part, index) =>
                  part.isMatch ? (
                    <span key={`${part.text}-${index}`} className="recipe-highlight-token">
                      {part.text}
                    </span>
                  ) : (
                    <span key={`${part.text}-${index}`}>{part.text}</span>
                  ),
                )}
                {code.endsWith('\n') ? <span className="recipe-textarea-trailing-space"> </span> : null}
              </>
            ) : (
              <span className="recipe-textarea-placeholder">{placeholder}</span>
            )}
          </>
        )}
        padding={12}
        textareaClassName="recipe-code-editor-textarea"
        preClassName="recipe-code-editor-highlight"
        style={{
          minHeight: 140,
          borderRadius: 14,
          border: '1px solid rgba(20, 33, 61, 0.14)',
          background: 'rgba(255, 255, 255, 0.96)',
          fontFamily: 'inherit',
          fontSize: '1rem',
          lineHeight: 1.5,
        }}
        textareaId={textareaId}
        placeholder={placeholder}
        onClick={(event) => setCaretIndex((event.currentTarget as HTMLTextAreaElement).selectionStart ?? 0)}
        onFocus={(event) => setCaretIndex((event.currentTarget as HTMLTextAreaElement).selectionStart ?? 0)}
        onKeyUp={(event) => setCaretIndex((event.currentTarget as HTMLTextAreaElement).selectionStart ?? 0)}
      />
      {autocomplete ? (
        <div className="recipe-autocomplete" role="listbox" aria-label="Sugestoes de insumos">
          {autocomplete.suggestions.map((suggestion) => (
            <button
              key={suggestion}
              type="button"
              className="recipe-autocomplete-option"
              onMouseDown={(event) => event.preventDefault()}
              onClick={() => applySuggestion(suggestion)}
            >
              {suggestion}
            </button>
          ))}
        </div>
      ) : null}
    </div>
  )
}

