function isTechnicalSheetConfigurationFieldApplicable(
  kind: TechnicalSheetKind,
  key: TechnicalSheetConfigurationFieldKey,
) {
  return technicalSheetConfigurationFieldDefinitions.some(
    (definition) => definition.key === key && definition.kinds.includes(kind),
  )
}

function getTechnicalSheetFieldDefaultRequired(kind: TechnicalSheetKind, key: TechnicalSheetConfigurationFieldKey) {
  if (key === 'sectors' || key === 'name' || key === 'family' || key === 'subfamily' || key === 'ingredients') {
    return true
  }
  if (key === 'outputUnit') {
    return true
  }
  if (key === 'portionSize' && kind === 'PREPARO') {
    return true
  }
  if (key === 'desiredCmvPercentage' && isCommercialTechnicalSheetKind(kind)) {
    return true
  }
  if (key === 'preparationMode' && kind === 'PREPARO') {
    return true
  }
  return false
}

function buildDefaultTechnicalSheetKindConfiguration(kind: TechnicalSheetKind): TechnicalSheetKindConfiguration {
  return Object.fromEntries(
    technicalSheetConfigurationFieldDefinitions.map((definition) => {
      const applicable = definition.kinds.includes(kind)
      return [
        definition.key,
        {
          visible: applicable,
          required: applicable ? getTechnicalSheetFieldDefaultRequired(kind, definition.key) : false,
        },
      ]
    }),
  ) as TechnicalSheetKindConfiguration
}

function buildDefaultTechnicalSheetFormSettings(): TechnicalSheetFormSettings {
  return {
    PREPARO: buildDefaultTechnicalSheetKindConfiguration('PREPARO'),
    EXECUCAO: buildDefaultTechnicalSheetKindConfiguration('EXECUCAO'),
    VENDA: buildDefaultTechnicalSheetKindConfiguration('VENDA'),
  }
}

