const getFirstAccessProfileForRole = (
  profiles: AccessProfileRecord[],
  role: CompanyUserRole,
) => profiles.find((profile) => profile.role === role && profile.isActive) ?? null

const normalizeSuggestionSet = (values: string[]) =>
  Array.from(
    new Map(
      values
        .map((value) => normalizeRegistrationText(value))
        .filter(Boolean)
        .map((value) => [value, value] as const),
    ).values(),
  ).sort((a, b) => a.localeCompare(b, 'pt-BR'))

const buildDefaultAccessProfiles = (companyId: number | null): AccessProfileRecord[] => {
  if (companyId === null) {
    return []
  }

  return [
    {
      id: -101,
      companyId,
      name: 'ADMINISTRATIVO',
      role: 'Administrativo',
      sectionAccess: defaultSectionAccessByRole('Administrativo'),
      catalogAccess: defaultCatalogAccessByRole('Administrativo'),
      isActive: true,
    },
    {
      id: -102,
      companyId,
      name: 'GESTOR',
      role: 'Gestor',
      sectionAccess: defaultSectionAccessByRole('Gestor'),
      catalogAccess: defaultCatalogAccessByRole('Gestor'),
      isActive: true,
    },
    {
      id: -103,
      companyId,
      name: 'COLABORADOR',
      role: 'Colaborador',
      sectionAccess: defaultSectionAccessByRole('Colaborador'),
      catalogAccess: defaultCatalogAccessByRole('Colaborador'),
      isActive: true,
    },
  ]
}

function buildCompanyAccessProfilesForSettings(
  companyId: number | null,
  accessProfiles: AccessProfileRecord[],
): AccessProfileRecord[] {
  const defaultProfiles = buildDefaultAccessProfiles(companyId)
  const storedProfiles =
    companyId === null
      ? []
      : accessProfiles.filter((profile) => profile.companyId === companyId)

  const defaultIds = new Set(defaultProfiles.map((profile) => profile.id))
  const mergedDefaults = defaultProfiles.map((profile) => {
    const override = storedProfiles.find((storedProfile) => storedProfile.id === profile.id)
    return override ?? profile
  })
  const customProfiles = storedProfiles.filter((profile) => !defaultIds.has(profile.id))

  return [...mergedDefaults, ...customProfiles]
}

function resolveStockModuleProfileIdsByRoles(
  companyId: number,
  accessProfiles: AccessProfileRecord[],
  roles: CompanyUserRole[],
) {
  const companyProfiles = buildCompanyAccessProfilesForSettings(companyId, accessProfiles)
  return companyProfiles
    .filter((profile) => roles.includes(profile.role))
    .map((profile) => profile.id)
}

