  const stockVariationReportRows = useMemo(() => {
    const rows: StockReportRow[] = []

    reportEligibleStockCenters.forEach((center) => {
      const snapshots = inventorySnapshotByCenterId.get(center.id) ?? null
      if (!snapshots) {
        return
      }

      const dates = Array.from(snapshots.keys()).sort((a, b) => a.localeCompare(b))
      if (dates.length === 0) {
        return
      }

      const latestDate = dates[dates.length - 1] ?? ''
      const previousDate = dates[dates.length - 2] ?? ''
      const latestSnapshot = snapshots.get(latestDate) ?? new Map<string, number>()
      const previousSnapshot = previousDate ? snapshots.get(previousDate) ?? new Map<string, number>() : new Map<string, number>()
      const aggregationKeys = new Set<string>([...latestSnapshot.keys(), ...previousSnapshot.keys()])

      aggregationKeys.forEach((aggregationKey) => {
        const metadata = inventoryAggregationMetadataByKey.get(aggregationKey)
        if (!metadata) {
          return
        }

        const latestQuantity = latestSnapshot.get(aggregationKey) ?? 0
        const previousQuantityValue = previousSnapshot.get(aggregationKey) ?? 0
        const variationQuantity = latestQuantity - previousQuantityValue
        const unitCost = stockUnitCostByAggregationKey.get(aggregationKey) ?? 0
        const totalCost = variationQuantity * unitCost
        if (latestQuantity === 0 && previousQuantityValue === 0) {
          return
        }

        const baseRow: StockReportRow = {
          id: `variation-${center.id}-${aggregationKey}`,
          main: metadata.main,
          secondary: `Atual ${formatDecimal(latestQuantity)} ${metadata.unit} • Anterior ${formatDecimal(previousQuantityValue)} ${metadata.unit}`,
          internalId: metadata.internalId,
          companyId: metadata.companyId,
          packageId: '',
          kind: metadata.kind,
          family: metadata.family,
          center: center.name,
          date: formatDateForDisplay(latestDate),
          status:
            previousDate === ''
              ? 'Primeira contagem'
              : variationQuantity > 0
                ? 'Alta'
                : variationQuantity < 0
                  ? 'Queda'
                  : 'Estavel',
          quantity: formatDecimal(variationQuantity),
          unitCost: formatCurrencyLabel(unitCost),
          totalCost: formatCurrencyLabel(totalCost),
          unit: metadata.unit,
          user: '',
          sortValues: {
            quantity: variationQuantity,
            unitCost,
            totalCost,
            date: latestDate,
          },
        }
        const productMatch = aggregationKey.startsWith('PRODUTO:') ? productById.get(aggregationKey.slice('PRODUTO:'.length)) ?? null : null
        rows.push(...(productMatch ? expandStockReportRowsByProductPackages(baseRow, productMatch, variationQuantity, { unitCost }) : [baseRow]))
      })
    })

    return rows.sort((a, b) => String(b.sortValues?.date ?? '').localeCompare(String(a.sortValues?.date ?? '')))
  }, [inventoryAggregationMetadataByKey, inventorySnapshotByCenterId, productById, reportEligibleStockCenters, stockUnitCostByAggregationKey])
