  function selectRecipePanelSheet(tab: RecipePanelTab, sheetId: number | null) {
    setRecipePanelSelectedId((current) => ({
      ...current,
      [tab]: sheetId,
    }))

    const selectedSheet = recipePanelSheetsByTab[tab].find((sheet) => sheet.id === sheetId) ?? null
    if (!selectedSheet) {
      setRecipePanelDesiredYield((current) => ({ ...current, [tab]: '' }))
      setRecipePanelRecipeCount((current) => ({ ...current, [tab]: '1' }))
      return
    }

    setRecipePanelSearch((current) => ({
      ...current,
      [tab]: selectedSheet.name,
    }))
    setRecipePanelDesiredYield((current) => ({
      ...current,
      [tab]: formatDecimal(getTechnicalSheetBaseYield(selectedSheet)),
    }))
    setRecipePanelRecipeCount((current) => ({
      ...current,
      [tab]: '1',
    }))
  }

  function handleRecipePanelSearchChange(tab: RecipePanelTab, value: string) {
    setRecipePanelSearch((current) => ({
      ...current,
      [tab]: value,
    }))

    const normalizedValue = normalizeRegistrationText(value.trim())
    if (!normalizedValue) {
      return
    }

    const matchedSheet =
      recipePanelSheetsByTab[tab].find((sheet) => sheet.name === normalizedValue) ??
      recipePanelSheetsByTab[tab].find((sheet) => sheet.productId === normalizedValue) ??
      recipePanelSheetsByTab[tab].find((sheet) => sheet.companyProductId === normalizedValue)

    if (matchedSheet) {
      selectRecipePanelSheet(tab, matchedSheet.id)
    }
  }

  function handleRecipePanelRecipeCountChange(tab: RecipePanelTab, value: string) {
    setRecipePanelRecipeCount((current) => ({
      ...current,
      [tab]: value,
    }))

    const selectedSheet = recipePanelSheetsByTab[tab].find((sheet) => sheet.id === recipePanelSelectedId[tab]) ?? null
    if (!selectedSheet) {
      return
    }

    const recipeCount = parseDecimal(value) ?? 0
    if (recipeCount <= 0) {
      setRecipePanelDesiredYield((current) => ({
        ...current,
        [tab]: '',
      }))
      return
    }

    setRecipePanelDesiredYield((current) => ({
      ...current,
      [tab]: formatDecimal(getTechnicalSheetBaseYield(selectedSheet) * recipeCount),
    }))
  }

  function handleRecipePanelDesiredYieldChange(tab: RecipePanelTab, value: string) {
    setRecipePanelDesiredYield((current) => ({
      ...current,
      [tab]: value,
    }))

    const selectedSheet = recipePanelSheetsByTab[tab].find((sheet) => sheet.id === recipePanelSelectedId[tab]) ?? null
    if (!selectedSheet) {
      return
    }

    const desiredYield = parseDecimal(value) ?? 0
    if (desiredYield <= 0) {
      setRecipePanelRecipeCount((current) => ({
        ...current,
        [tab]: '',
      }))
      return
    }

    const baseYield = getTechnicalSheetBaseYield(selectedSheet)
    setRecipePanelRecipeCount((current) => ({
      ...current,
      [tab]: formatDecimal(desiredYield / baseYield),
    }))
  }

