  function updateServiceItemForm<K extends keyof ServiceItemFormState>(field: K, value: ServiceItemFormState[K]) {
    if (
      field === 'companyProductId' ||
      field === 'manufacturerCode' ||
      field === 'name' ||
      field === 'sizeValue' ||
      field === 'family' ||
      field === 'subfamily'
    ) {
      setServiceItemForm((current) => ({
        ...current,
        [field]: normalizeRegistrationText(String(value)) as ServiceItemFormState[K],
      }))
      return
    }

    if (field === 'sectors') {
      setServiceItemForm((current) => ({
        ...current,
        sectors: (value as string[]).map((item) => normalizeRegistrationText(item)).filter(Boolean),
      }))
      return
    }

    setServiceItemForm((current) => ({ ...current, [field]: value }))
  }

  function updateServiceItemImage(file: File | null) {
    if (!file || !file.type.startsWith('image/')) {
      return
    }

    const reader = new FileReader()
    reader.onload = () => {
      const result = typeof reader.result === 'string' ? reader.result : ''
      setServiceItemForm((current) => ({
        ...current,
        imageDataUrl: result,
      }))
    }
    reader.readAsDataURL(file)
  }

  async function saveServiceItem() {
    if (isSavingServiceItem) {
      return
    }

    const normalizedName = normalizeRegistrationText(serviceItemForm.name.trim())
    const normalizedFamily = normalizeRegistrationText(serviceItemForm.family.trim())
    const normalizedSubfamily = normalizeRegistrationText(serviceItemForm.subfamily.trim())
    const normalizedSectors = serviceItemForm.sectors
      .map((sector) => normalizeRegistrationText(sector.trim()))
      .filter(Boolean)
    const errors: string[] = []

    if (!normalizedName) {
      errors.push('nome do item obrigatorio')
    }
    if (!normalizedFamily) {
      errors.push('tipo do item obrigatorio')
    }
    if (!normalizedSubfamily) {
      errors.push('material do item obrigatorio')
    }
    if (normalizedSectors.length === 0) {
      errors.push('ao menos 1 setor obrigatorio')
    }

    if (errors.length > 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar item',
        message: `Erro: ${errors.join('; ')}.`,
      })
      return
    }

    const normalizedNameKey = buildNormalizedRegistrationNameKey(normalizedName)
    const duplicateServiceItem = serviceItems.find(
      (item) =>
        item.companyId === (currentCompanyId ?? 0) &&
        item.id !== editingServiceItemId &&
        buildNormalizedRegistrationNameKey(item.name) === normalizedNameKey,
    )
    if (duplicateServiceItem) {
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar item',
        message: `Ja existe um item cadastrado com o nome ${normalizedName}.`,
      })
      return
    }

    const itemToSave: ServiceItemRecord = {
      companyId: currentCompanyId ?? 0,
      id: generatedServiceItemId,
      kind: serviceItemForm.kind,
      companyProductId: normalizeRegistrationText(serviceItemForm.companyProductId.trim()),
      manufacturerCode: normalizeRegistrationText(serviceItemForm.manufacturerCode.trim()),
      name: normalizedName,
      sizeValue: serviceItemForm.sizeValue.trim(),
      sizeUnit: serviceItemForm.sizeUnit,
      emptyWeight: serviceItemForm.emptyWeight.trim(),
      controlUnit: 'UNIT',
      family: normalizedFamily,
      subfamily: normalizedSubfamily,
      sectors: normalizedSectors,
      imageDataUrl: serviceItemForm.imageDataUrl,
      isActive: hasServiceItemPackages,
      packages: serviceItemPackages.map((entry) => ({ ...entry, barcode: '', grossWeightGrams: '', packagingWeightGrams: '' })),
    }

    setIsSavingServiceItem(true)
    setSaveProgressState({
      title: 'Registrando item',
      message: 'Registrando, aguarde. Nao feche a tela nem clique novamente em salvar.',
    })
    try {
      await upsertServiceItemRecordOnApi(itemToSave, editingServiceItemId)
    } catch (error) {
      console.error(error)
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar item',
        message: error instanceof Error ? error.message : 'Erro ao salvar item no servidor.',
      })
      return
    } finally {
      setIsSavingServiceItem(false)
      setSaveProgressState(null)
    }

    setServiceItems((current) =>
      editingServiceItemId
        ? current.map((entry) => (entry.id === editingServiceItemId ? itemToSave : entry))
        : [itemToSave, ...current],
    )
    await refreshAppCatalogRecordsFromApi()
    if (restoreTechnicalSheetDraftWithCreatedServiceItem(itemToSave.id, itemToSave.name)) {
      setIsTechnicalSheetServiceItemModalOpen(false)
      setSaveFeedback({
        status: 'success',
        title: 'Item salvo com sucesso',
        message: 'O recipiente foi cadastrado e vinculado a ficha de execucao.',
      })
      return
    }
    setSaveFeedback({
      status: 'success',
      title: 'Item salvo com sucesso',
      message: hasServiceItemPackages
        ? 'O item foi salvo e ja esta apto para uso porque possui embalagem cadastrada.'
        : 'O item foi salvo como rascunho. Cadastre ao menos uma embalagem para liberar o uso.',
    })
  }

