  function requestDeleteSector(sector: string) {
    if (!isManagerUser && !isSystemAdmin) {
      setSaveFeedback({
        status: 'error',
        title: 'Exclusao nao permitida',
        message: 'Erro: apenas usuarios com perfil Gestor ou Master podem excluir setores.',
      })
      return
    }

    const normalizedSector = normalizeRegistrationText(sector)
    if (!normalizedSector) {
      return
    }

    const matchingProducts = products.filter(
      (product) =>
        (currentCompanyId === null || product.companyId === currentCompanyId) &&
        product.sectors.includes(normalizedSector),
    )
    const impactedProducts = matchingProducts
      .map((product) => product.name)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))
    const orphanProducts = matchingProducts
      .filter((product) => product.sectors.length === 1)
      .map((product) => product.name)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))

    const matchingUsers = users.filter(
      (user) =>
        userBelongsToCompany(user, currentCompanyId) &&
        user.sectors.includes(normalizedSector),
    )
    const impactedUsers = matchingUsers
      .map((user) => user.fullName)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))
    const orphanUsers = matchingUsers
      .filter((user) => user.sectors.length === 1)
      .map((user) => user.fullName)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))

    const matchingServiceItems = serviceItems.filter(
      (item) =>
        (currentCompanyId === null || item.companyId === currentCompanyId) &&
        item.sectors.includes(normalizedSector),
    )
    const impactedServiceItems = matchingServiceItems
      .map((item) => item.name)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))
    const orphanServiceItems = matchingServiceItems
      .filter((item) => item.sectors.length === 1)
      .map((item) => item.name)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))

    setSectorHideState({
      sector: normalizedSector,
      impactedProducts: [...impactedProducts, ...impactedServiceItems].sort((a, b) => a.localeCompare(b, 'pt-BR')),
      impactedUsers,
      orphanProducts: [...orphanProducts, ...orphanServiceItems].sort((a, b) => a.localeCompare(b, 'pt-BR')),
      orphanUsers,
      resolution: 'replace',
      replacementSector: '',
    })
  }

  function requestDeleteTaxonomy(kind: TaxonomyDeleteKind, rawValue: string) {
    const deletionAllowed =
      kind === 'productFamily'
        ? canDeleteFamilies
        : kind === 'productSubfamily'
        ? canDeleteSubfamilies
        : kind === 'serviceItemFamily'
        ? canDeleteItemTypes
        : canDeleteMaterials

    if (!deletionAllowed) {
      setSaveFeedback({
        status: 'error',
        title: 'Exclusao nao permitida',
        message: 'Erro: seu perfil nao possui permissao para excluir esse cadastro auxiliar.',
      })
      return
    }

    const value = normalizeRegistrationText(rawValue)
    if (!value) {
      return
    }

    const matchingProducts =
      kind === 'productFamily'
        ? products.filter(
            (product) =>
              (currentCompanyId === null || product.companyId === currentCompanyId) &&
              product.family === value,
          )
        : kind === 'productSubfamily'
        ? products.filter(
            (product) =>
              (currentCompanyId === null || product.companyId === currentCompanyId) &&
              product.subfamily === value,
          )
        : []

    const matchingTechnicalSheets =
      kind === 'productFamily'
        ? technicalSheets.filter(
            (sheet) =>
              (currentCompanyId === null || sheet.companyId === currentCompanyId) &&
              sheet.family === value,
          )
        : kind === 'productSubfamily'
        ? technicalSheets.filter(
            (sheet) =>
              (currentCompanyId === null || sheet.companyId === currentCompanyId) &&
              sheet.subfamily === value,
          )
        : []

    const matchingServiceItems =
      kind === 'serviceItemFamily'
        ? serviceItems.filter(
            (item) =>
              (currentCompanyId === null || item.companyId === currentCompanyId) &&
              item.family === value,
          )
        : kind === 'serviceItemSubfamily'
        ? serviceItems.filter(
            (item) =>
              (currentCompanyId === null || item.companyId === currentCompanyId) &&
              item.subfamily === value,
          )
        : []

    setTaxonomyDeleteState({
      kind,
      value,
      impactedProducts: matchingProducts.map((item) => item.name).sort((a, b) => a.localeCompare(b, 'pt-BR')),
      impactedTechnicalSheets: matchingTechnicalSheets.map((item) => item.name).sort((a, b) => a.localeCompare(b, 'pt-BR')),
      impactedServiceItems: matchingServiceItems.map((item) => item.name).sort((a, b) => a.localeCompare(b, 'pt-BR')),
      resolution: 'replace',
      replacementValue: '',
    })
  }

  function requestDeleteInventoryStorageLocation(rawValue: string) {
    if (!canDeleteSectors && !isSystemAdmin) {
      setSaveFeedback({
        status: 'error',
        title: 'Exclusao nao permitida',
        message: 'Erro: apenas usuarios com permissao para excluir setores podem excluir locais de armazenamento.',
      })
      return
    }

    const location = normalizeRegistrationText(rawValue)
    if (!location) {
      return
    }

    const impactedCounts = inventoryCounts
      .filter((record) => record.companyId === currentCompanyId && record.storageLocation === location)
      .map((record) => `${record.countedAt} • ${record.technicalSheetName} • ${record.createdByUserName}`)
      .sort((a, b) => a.localeCompare(b, 'pt-BR'))

    setInventoryStorageLocationDeleteState({
      location,
      impactedCounts,
      resolution: impactedCounts.length > 0 ? 'replace' : 'inactivate',
      replacementLocation: '',
    })
  }

  function confirmDeleteInventoryStorageLocation() {
    if (!inventoryStorageLocationDeleteState) {
      return
    }

    const replacementLocation = normalizeRegistrationText(inventoryStorageLocationDeleteState.replacementLocation)
    if (inventoryStorageLocationDeleteState.resolution === 'replace' && !replacementLocation) {
      setSaveFeedback({
        status: 'error',
        title: 'Defina a resolucao do local',
        message: 'Erro: escolha um novo local para substituir os registros impactados.',
      })
      return
    }
    if (
      inventoryStorageLocationDeleteState.resolution === 'replace' &&
      replacementLocation === inventoryStorageLocationDeleteState.location
    ) {
      setSaveFeedback({
        status: 'error',
        title: 'Defina a resolucao do local',
        message: 'Erro: o novo local precisa ser diferente do local que sera excluido.',
      })
      return
    }

    if (inventoryStorageLocationDeleteState.resolution === 'replace') {
      setInventoryCounts((current) =>
        current.map((record) =>
          record.companyId === currentCompanyId && record.storageLocation === inventoryStorageLocationDeleteState.location
            ? { ...record, storageLocation: replacementLocation }
            : record,
        ),
      )
      setInventoryStorageLocations((current) => {
        const next = current.map((location) =>
          location.companyId === currentCompanyId && location.name === inventoryStorageLocationDeleteState.location
            ? { ...location, isActive: false }
            : location,
        )

        const hasReplacement = next.some(
          (location) => location.companyId === currentCompanyId && location.name === replacementLocation,
        )
        if (hasReplacement) {
          return next.map((location) =>
            location.companyId === currentCompanyId && location.name === replacementLocation
              ? { ...location, isActive: true }
              : location,
          )
        }
        return [...next, { companyId: currentCompanyId ?? 0, name: replacementLocation, isActive: true }]
      })
      setInventoryForm((current) => ({
        ...current,
        storageLocation:
          current.storageLocation === inventoryStorageLocationDeleteState.location ? replacementLocation : current.storageLocation,
      }))
    } else {
      setInventoryStorageLocations((current) =>
        current.map((location) =>
          location.companyId === currentCompanyId && location.name === inventoryStorageLocationDeleteState.location
            ? { ...location, isActive: false }
            : location,
        ),
      )
      setInventoryForm((current) => ({
        ...current,
        storageLocation:
          current.storageLocation === inventoryStorageLocationDeleteState.location ? '' : current.storageLocation,
      }))
    }

    setInventoryStorageLocationDeleteState(null)
  }

  function confirmHideSector() {
    if (!sectorHideState) {
      return
    }

    const replacementSector = normalizeRegistrationText(sectorHideState.replacementSector)
    const requiresResolution =
      sectorHideState.orphanProducts.length > 0 || sectorHideState.orphanUsers.length > 0

    if (requiresResolution && sectorHideState.resolution === 'replace' && !replacementSector) {
      setSaveFeedback({
        status: 'error',
        title: 'Defina a resolucao do setor',
        message: 'Erro: escolha um novo setor para substituir os cadastros que ficariam sem setor.',
      })
      return
    }

    if (requiresResolution && sectorHideState.resolution === 'replace' && replacementSector === sectorHideState.sector) {
      setSaveFeedback({
        status: 'error',
        title: 'Defina a resolucao do setor',
        message: 'Erro: o novo setor precisa ser diferente do setor que sera excluido.',
      })
      return
    }

    setProducts((current) =>
      current.map((product) =>
        product.sectors.includes(sectorHideState.sector)
          ? {
              ...product,
              sectors: resolveSectorDeletion(
                product.sectors,
                sectorHideState.sector,
                sectorHideState.resolution,
                replacementSector,
              ),
              isActive:
                sectorHideState.resolution === 'inactivate' &&
                product.sectors.length === 1 &&
                product.sectors[0] === sectorHideState.sector
                  ? false
                  : product.isActive,
            }
          : product,
      ),
    )
    setServiceItems((current) =>
      current.map((item) =>
        item.sectors.includes(sectorHideState.sector)
          ? {
              ...item,
              sectors: resolveSectorDeletion(
                item.sectors,
                sectorHideState.sector,
                sectorHideState.resolution,
                replacementSector,
              ),
              isActive:
                sectorHideState.resolution === 'inactivate' &&
                item.sectors.length === 1 &&
                item.sectors[0] === sectorHideState.sector
                  ? false
                  : item.isActive,
            }
          : item,
      ),
    )
    setUsers((current) =>
      current.map((user) =>
        user.sectors.includes(sectorHideState.sector)
          ? {
              ...user,
              sectors: resolveSectorDeletion(
                user.sectors,
                sectorHideState.sector,
                sectorHideState.resolution,
                replacementSector,
              ),
              isActive:
                sectorHideState.resolution === 'inactivate' &&
                user.sectors.length === 1 &&
                user.sectors[0] === sectorHideState.sector
                  ? false
                  : user.isActive,
            }
          : user,
      ),
    )
    setProductForm((current) => ({
      ...current,
      sectors: resolveSectorDeletion(
        current.sectors,
        sectorHideState.sector,
        sectorHideState.resolution,
        replacementSector,
      ),
    }))
    setUserForm((current) => ({
      ...current,
      sectors: resolveSectorDeletion(
        current.sectors,
        sectorHideState.sector,
        sectorHideState.resolution,
        replacementSector,
      ),
    }))
    setServiceItemForm((current) => ({
      ...current,
      sectors: resolveSectorDeletion(
        current.sectors,
        sectorHideState.sector,
        sectorHideState.resolution,
        replacementSector,
      ),
    }))
    setSectorHideState(null)
  }

  function confirmDeleteTaxonomy() {
    if (!taxonomyDeleteState) {
      return
    }

    const replacementValue = normalizeRegistrationText(taxonomyDeleteState.replacementValue)
    if (taxonomyDeleteState.resolution === 'replace' && !replacementValue) {
      setSaveFeedback({
        status: 'error',
        title: 'Defina a resolucao do cadastro',
        message: 'Erro: escolha um novo valor para substituir os cadastros impactados.',
      })
      return
    }
    if (taxonomyDeleteState.resolution === 'replace' && replacementValue === taxonomyDeleteState.value) {
      setSaveFeedback({
        status: 'error',
        title: 'Defina a resolucao do cadastro',
        message: 'Erro: o novo valor precisa ser diferente do valor que sera excluido.',
      })
      return
    }

    if (taxonomyDeleteState.kind === 'productFamily' || taxonomyDeleteState.kind === 'productSubfamily') {
      const field = taxonomyDeleteState.kind === 'productFamily' ? 'family' : 'subfamily'
      setProducts((current) =>
        current.map((product) =>
          product[field] === taxonomyDeleteState.value
            ? {
                ...product,
                [field]: taxonomyDeleteState.resolution === 'replace' ? replacementValue : '',
                isActive: taxonomyDeleteState.resolution === 'inactivate' ? false : product.isActive,
              }
            : product,
        ),
      )
      setTechnicalSheets((current) =>
        current.map((sheet) =>
          sheet[field] === taxonomyDeleteState.value
            ? {
                ...sheet,
                [field]: taxonomyDeleteState.resolution === 'replace' ? replacementValue : '',
                isActive: taxonomyDeleteState.resolution === 'inactivate' ? false : sheet.isActive,
              }
            : sheet,
        ),
      )
      setProductForm((current) => ({
        ...current,
        [field]:
          current[field] === taxonomyDeleteState.value
            ? taxonomyDeleteState.resolution === 'replace'
              ? replacementValue
              : ''
            : current[field],
      }))
      setTechnicalSheetForm((current) => ({
        ...current,
        [field]:
          current[field] === taxonomyDeleteState.value
            ? taxonomyDeleteState.resolution === 'replace'
              ? replacementValue
              : ''
            : current[field],
      }))
    } else {
      const field = taxonomyDeleteState.kind === 'serviceItemFamily' ? 'family' : 'subfamily'
      setServiceItems((current) =>
        current.map((item) =>
          item[field] === taxonomyDeleteState.value
            ? {
                ...item,
                [field]: taxonomyDeleteState.resolution === 'replace' ? replacementValue : '',
                isActive: taxonomyDeleteState.resolution === 'inactivate' ? false : item.isActive,
              }
            : item,
        ),
      )
      setServiceItemForm((current) => ({
        ...current,
        [field]:
          current[field] === taxonomyDeleteState.value
            ? taxonomyDeleteState.resolution === 'replace'
              ? replacementValue
              : ''
            : current[field],
      }))
    }

    setTaxonomyDeleteState(null)
  }

  function updateUserFormField<K extends keyof UserFormState>(field: K, value: UserFormState[K]) {
    if (field === 'fullName') {
      setUserForm((current) => ({
        ...current,
        fullName: normalizeRegistrationText(String(value)),
      }))
      return
    }

    if (field === 'username') {
      setUserForm((current) => ({
        ...current,
        username: String(value),
      }))
      return
    }

    if (field === 'sectors') {
      setUserForm((current) => ({
        ...current,
        sectors: (value as string[]).map((item) => normalizeRegistrationText(item)).filter(Boolean),
      }))
      return
    }

    if (field === 'companyIds') {
      setUserForm((current) => ({
        ...current,
        companyIds: Array.from(
          new Set((value as number[]).filter((companyId): companyId is number => typeof companyId === 'number')),
        ),
      }))
      return
    }

    setUserForm((current) => ({ ...current, [field]: value }))
  }

  function updateUserAccessProfile(profileId: string) {
    const targetProfile =
      assignableAccessProfiles.find((profile) => String(profile.id) === profileId) ?? null

    setUserForm((current) => ({
      ...current,
      role: targetProfile?.role ?? current.role,
      accessProfileId: profileId,
      sectionAccess: targetProfile?.sectionAccess ?? current.sectionAccess,
      catalogAccess: targetProfile?.catalogAccess ?? current.catalogAccess,
    }))
  }

