  function editStockCenter(stockCenterId: number) {
    const targetStockCenter = stockCenters.find((center) => center.id === stockCenterId && center.companyId === currentCompanyId) ?? null
    if (!targetStockCenter) {
      return
    }

    setStockCenterDraftBeforeEdit({
      form: {
        ...stockCenterForm,
        userIds: [...stockCenterForm.userIds],
        minimumStocks: stockCenterForm.minimumStocks.map((item) => ({ ...item })),
      },
      stockCenterMinimumSearch,
    })
    setEditingStockCenterId(stockCenterId)
    setStockCenterForm({
      name: targetStockCenter.name,
      code: targetStockCenter.code,
      sector: targetStockCenter.sector,
      userIds: targetStockCenter.userIds,
      responsibleUserIds: targetStockCenter.responsibleUserIds.map((userId) => String(userId)),
      isProducer: targetStockCenter.isProducer,
      producedTechnicalSheetIds: targetStockCenter.producedTechnicalSheetIds.map((sheetId) => String(sheetId)),
      minimumStocks: targetStockCenter.minimumStocks,
    })
    setStockCenterMinimumSearch('')
    setStockCenterUserInput('')
    setStockCenterResponsibleInput('')
    setStockCenterProducedSheetInput('')
    setIsStockCenterModalOpen(true)
  }

  function saveStockCenter() {
    if (currentCompanyId === null) {
      return
    }

    if (!stockCenterForm.name.trim()) {
      setSaveFeedback({
        status: 'error',
        title: 'Centro de estoque incompleto',
        message: 'Erro: informe o nome do centro de estoque.',
      })
      return
    }

    if (!stockCenterForm.sector.trim()) {
      setSaveFeedback({
        status: 'error',
        title: 'Centro de estoque incompleto',
        message: 'Erro: selecione o setor responsavel pelo centro de estoque.',
      })
      return
    }

    const validUserIds = Array.from(new Set(stockCenterForm.userIds)).filter((userId) => {
      const user = users.find((candidate) => candidate.id === userId && userBelongsToCompany(candidate, currentCompanyId))
      return user?.isActive === true && user.sectors.includes(stockCenterForm.sector)
    })

    if (validUserIds.length === 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Centro de estoque incompleto',
        message: 'Erro: selecione ao menos um usuario ativo do setor escolhido.',
      })
      return
    }

    const responsibleUserIds = Array.from(new Set(stockCenterForm.responsibleUserIds.map((value) => Number(value)))).filter(
      (userId) => Number.isFinite(userId) && validUserIds.includes(userId),
    )
    if (responsibleUserIds.length === 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Centro de estoque incompleto',
        message: 'Erro: selecione ao menos um usuario responsavel pelo centro de estoque.',
      })
      return
    }

    const validProducedTechnicalSheetIds = Array.from(
      new Set(stockCenterForm.producedTechnicalSheetIds.map((value) => Number(value))),
    ).filter(
      (sheetId) =>
        Number.isFinite(sheetId) &&
        producerTechnicalSheets.some((sheet) => sheet.id === sheetId),
    )

    const normalizedCode = normalizeRegistrationText(generatedStockCenterCode)

    const centerToSave: StockCenterRecord = {
      id: editingStockCenterId ?? Date.now(),
      companyId: currentCompanyId,
      name: normalizeRegistrationText(stockCenterForm.name),
      sector: normalizeRegistrationText(stockCenterForm.sector),
      code: normalizedCode,
      userIds: validUserIds,
      responsibleUserIds,
      isProducer: stockCenterForm.isProducer,
      producedTechnicalSheetIds: stockCenterForm.isProducer ? validProducedTechnicalSheetIds : [],
      minimumStocks: stockCenterForm.minimumStocks
        .filter((item) => item.minimumQuantity.trim() !== '')
        .map((item) => ({
          kind: item.kind,
          technicalSheetId: item.technicalSheetId,
          productId: item.productId,
          serviceItemId: item.serviceItemId,
          packageId: item.packageId,
          minimumQuantity: item.minimumQuantity.trim(),
        })),
      isActive: editingStockCenterId === null ? true : stockCenters.find((center) => center.id === editingStockCenterId)?.isActive ?? true,
    }

    setStockCenters((current) =>
      editingStockCenterId === null
        ? [...current, centerToSave]
        : current.map((center) => (center.id === editingStockCenterId ? centerToSave : center)),
    )
    setTechnicalSheets((current) =>
      current.map((sheet) => {
        if (sheet.kind !== 'PREPARO') {
          return sheet
        }

        const remainingProductionCenters = (sheet.productionCenters ?? []).filter(
          (assignment) => assignment.stockCenterId !== centerToSave.id,
        )
        const prepMinimumQuantity =
          centerToSave.minimumStocks.find(
            (item) => item.kind === 'PREPARO' && item.technicalSheetId === sheet.id,
          )?.minimumQuantity ?? ''

        if (!centerToSave.isProducer || !centerToSave.producedTechnicalSheetIds.includes(sheet.id)) {
          return {
            ...sheet,
            productionCenters: remainingProductionCenters,
          }
        }

        return {
          ...sheet,
          productionCenters: [
            ...remainingProductionCenters,
            {
              stockCenterId: centerToSave.id,
              minimumQuantity: prepMinimumQuantity,
            },
          ],
        }
      }),
    )
    if (editingStockCenterId === null) {
      setStockCenterForm(emptyStockCenterForm())
      setStockCenterUserInput('')
      setStockCenterResponsibleInput('')
      setStockCenterProducedSheetInput('')
      setStockCenterMinimumSearch('')
    } else {
      setIsStockCenterModalOpen(false)
      setEditingStockCenterId(null)
      setStockCenterForm(stockCenterDraftBeforeEdit?.form ?? emptyStockCenterForm())
      setStockCenterMinimumSearch(stockCenterDraftBeforeEdit?.stockCenterMinimumSearch ?? '')
      setStockCenterUserInput('')
      setStockCenterResponsibleInput('')
      setStockCenterProducedSheetInput('')
      setStockCenterDraftBeforeEdit(null)
    }
    setSaveFeedback({
      status: 'success',
      title: editingStockCenterId === null ? 'Centro de estoque salvo com sucesso' : 'Centro de estoque atualizado com sucesso',
      message:
        editingStockCenterId === null
          ? 'O centro de estoque foi cadastrado e ja pode ser usado nos fluxos de controle.'
          : 'As configuracoes do centro de estoque foram atualizadas.',
    })
  }

  function toggleStockCenterStatus(stockCenterId: number) {
    setStockCenters((current) =>
      current.map((center) =>
        center.id === stockCenterId ? { ...center, isActive: !center.isActive } : center,
      ),
    )
  }

  function deleteStockCenter(stockCenterId: number) {
    setStockCenters((current) => current.filter((center) => center.id !== stockCenterId))
    if (editingStockCenterId === stockCenterId) {
      setEditingStockCenterId(null)
      setStockCenterForm(emptyStockCenterForm())
    }
  }

  function buildRequisitionDraftLines(center: StockCenterRecord): RequisitionDraftLine[] {
    const minimumByKey = new Map(
      center.minimumStocks.map((minimumStock) => [buildStockCenterMinimumEntryKey(minimumStock), minimumStock] as const),
    )

    return stockCenterMinimumRows
      .filter((row) => row.kind !== 'ITEM' || row.baseUnit === 'UNIT')
      .filter((row) => !(row.kind === 'PREPARO' && row.technicalSheetId !== null && center.producedTechnicalSheetIds.includes(row.technicalSheetId)))
      .map((row) => {
        const minimumStock = minimumByKey.get(row.key) ?? null
        const configuredMinimum = parseDecimal(minimumStock?.minimumQuantity ?? '') ?? 0
        const requiredBaseQuantity = configuredMinimum * row.baseQuantity
        const currentBaseQuantity =
          selectedRequisitionCurrentQuantityByKey.get(
            buildInventoryAggregationKey({
              kind: row.kind,
              technicalSheetId: row.technicalSheetId,
              productId: row.productId,
              serviceItemId: row.serviceItemId,
            }),
          ) ?? 0
        const shortageBaseQuantity = Math.max(requiredBaseQuantity - currentBaseQuantity, 0)
        const suggestedQuantity = row.baseQuantity > 0 ? shortageBaseQuantity / row.baseQuantity : 0
        const destinationType = row.kind === 'PREPARO' ? 'PRODUCOES' : 'DISTRIBUICAO'
        const producerAssignments =
          row.kind === 'PREPARO' && row.technicalSheetId !== null
            ? (
                technicalSheets.find((sheet) => sheet.id === row.technicalSheetId && sheet.kind === 'PREPARO')?.productionCenters ??
                []
              )
                .filter((assignment) => assignment.stockCenterId !== center.id)
            : []
        const producerCenters = producerAssignments
          .map((assignment) => stockCenters.find((candidateCenter) => candidateCenter.id === assignment.stockCenterId)?.name ?? null)
          .filter((value): value is string => Boolean(value))
        const destinationCenterId = destinationType === 'PRODUCOES' && producerAssignments.length === 1 ? producerAssignments[0].stockCenterId : null
        const destinationCenterName = destinationType === 'PRODUCOES' && producerCenters.length === 1 ? producerCenters[0] : ''

        return {
          key: row.key,
          kind: row.kind,
          technicalSheetId: row.technicalSheetId,
          productId: row.productId,
          serviceItemId: row.serviceItemId,
          packageId: row.packageId,
          itemName: row.name,
          itemTypeLabel: row.typeLabel,
          family: row.family,
          suggestedQuantity: formatDecimal(suggestedQuantity),
          requestedQuantity: formatDecimal(suggestedQuantity),
          requestUnitLabel: getRequisitionRequestUnitLabel(row),
          currentQuantity: formatDecimal(currentBaseQuantity),
          currentUnitLabel: formatControlUnitShort(row.baseUnit),
          minimumDefinitionLabel: formatStockCenterMinimumDefinition(minimumStock?.minimumQuantity ?? '', row),
          destinationType,
          destinationCenterId,
          destinationCenterName,
          destinationLabel:
            destinationType === 'PRODUCOES'
              ? producerCenters.length > 0
                ? `CENTRO(S) PRODUTOR(ES): ${producerCenters.join(', ')}`
                : 'CENTRO PRODUTOR NAO DEFINIDO'
              : 'ESTOQUE CENTRAL DE DISTRIBUICAO',
          receiptStatus: 'PENDING',
        } satisfies RequisitionDraftLine
      })
      .sort((a, b) => a.itemName.localeCompare(b.itemName, 'pt-BR'))
  }

  function generateRequisitionDraft() {
    if (!selectedRequisitionStockCenter) {
      setSaveFeedback({
        status: 'error',
        title: 'Requisicao incompleta',
        message: 'Selecione um centro de estoque para montar a requisicao.',
      })
      return
    }

    const nextDraftLines = buildRequisitionDraftLines(selectedRequisitionStockCenter)
    if (nextDraftLines.length === 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Requisicao sem itens',
        message: 'Nao ha itens com estoque minimo configurado para este centro de estoque.',
      })
      return
    }

    setEditingRequisitionId(null)
    setRequisitionDraftLines(nextDraftLines)
    setRequisitionDraftSearch('')
    setIsRequisitionEditModalOpen(false)
    setRequisitionTab('new')
  }

  function saveRequisitionDraft() {
    if (currentCompanyId === null || !selectedRequisitionStockCenter) {
      setSaveFeedback({
        status: 'error',
        title: 'Requisicao incompleta',
        message: 'Selecione um centro de estoque para salvar a requisicao.',
      })
      return
    }

    const linesToSave = requisitionDraftLines.filter((line) => (parseDecimal(line.requestedQuantity) ?? 0) > 0)
    if (linesToSave.length === 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Requisicao vazia',
        message: 'Defina ao menos uma quantidade solicitada maior que zero.',
      })
      return
    }

    const requisitionReferenceDate = selectedRequisitionLatestInventoryDate || getTodayDateInputValue()
    const now = new Date().toISOString()
    if (editingRequisitionId === null) {
      const nextRequisition: RequisitionRecord = {
        id: Date.now(),
        companyId: currentCompanyId,
        requisitionGroupId: Date.now(),
        stockCenterId: selectedRequisitionStockCenter.id,
        stockCenterName: selectedRequisitionStockCenter.name,
        supplyCenterId: null,
        supplyCenterName: '',
        sector: selectedRequisitionStockCenter.sector,
        countedAt: requisitionReferenceDate,
        status: 'PENDING_APPROVAL',
        editScope: 'FULL',
        lines: linesToSave,
        createdAt: now,
        createdByUserId: currentAppUser?.id ?? null,
        createdByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        approvedAt: '',
        approvedByUserId: null,
        approvedByUserName: '',
        sentAt: '',
        sentByUserId: null,
        sentByUserName: '',
        preparedAt: '',
        preparedByUserId: null,
        preparedByUserName: '',
        receivedAt: '',
        receivedByUserId: null,
        receivedByUserName: '',
        lastUpdatedAt: now,
        lastUpdatedByUserId: currentAppUser?.id ?? null,
        lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
      }
      setRequisitions((current) => [nextRequisition, ...current])
      setSaveFeedback({
        status: 'success',
        title: 'Requisicao criada com sucesso',
        message: 'A requisicao foi criada e agora aguarda aprovacao do responsavel pelo centro de estoque.',
      })
    } else {
      const currentRecord = requisitions.find((record) => record.id === editingRequisitionId) ?? null
      if (!currentRecord) {
        return
      }

      const editedByResponsible =
        currentAppUser &&
        currentRecord.createdByUserId !== currentAppUser.id &&
        canApproveRequisition(currentRecord)

      setRequisitions((current) =>
        current.map((record) =>
          record.id === editingRequisitionId
          ? {
              ...record,
              lines: linesToSave,
              status: record.status,
              editScope: record.editScope,
              lastUpdatedAt: now,
              lastUpdatedByUserId: currentAppUser?.id ?? null,
              lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
              }
            : record,
        ),
      )

      if (editedByResponsible) {
        notifyRequisitionStakeholders(
          currentRecord,
          `A REQUISICAO DO CENTRO ${currentRecord.stockCenterName} FOI EDITADA PELO RESPONSAVEL DO CENTRO.`,
        )
      }

      setSaveFeedback({
        status: 'success',
        title: 'Requisicao atualizada com sucesso',
        message: 'As quantidades pedidas foram atualizadas.',
      })
    }

    setEditingRequisitionId(null)
    setRequisitionDraftLines([])
    setRequisitionDraftSearch('')
    setIsRequisitionEditModalOpen(false)
    setRequisitionTab('history')
  }

  function canApproveRequisition(record: RequisitionRecord) {
    return (
      isSystemAdmin ||
      requisitionApprovalCenters.some((center) => center.id === record.stockCenterId)
    )
  }

  function canManageRequisition(record: RequisitionRecord) {
    return (
      isSystemAdmin ||
      (currentAppUser
        ? record.createdByUserId === currentAppUser.id || canApproveRequisition(record)
        : false)
    )
  }

  function canManageSupplyRequisition(record: RequisitionRecord) {
    return (
      isSystemAdmin ||
      (currentAppUser && record.supplyCenterId !== null
        ? supplyResponsibleCenters.some((center) => center.id === record.supplyCenterId)
        : false)
    )
  }

  function canReceiveRequisition(record: RequisitionRecord) {
    return (
      isSystemAdmin ||
      (currentAppUser
        ? requisitionEligibleStockCenters.some((center) => center.id === record.stockCenterId)
        : false)
    )
  }

  function getSupplyRequisitionStockShortageMessage(record: RequisitionRecord) {
    if (record.supplyCenterId === null) {
      return ''
    }

    const shortages = record.lines
      .map((line) => {
        const aggregationKey = buildInventoryAggregationKey({
          kind: line.kind,
          technicalSheetId: line.kind === 'PREPARO' ? line.technicalSheetId : null,
          productId: line.kind === 'PRODUTO' ? line.productId : '',
          serviceItemId: line.kind === 'ITEM' ? line.serviceItemId : '',
        })
        const availableQuantity =
          latestInventoryQuantityByCenterAndAggregation.get(`${record.supplyCenterId}:${aggregationKey}`) ?? 0
        const movementConfig = getRequisitionStockMovementConfig(line)
        const requestedQuantity = (parseDecimal(line.requestedQuantity) ?? 0) * movementConfig.multiplier
        const shortage = requestedQuantity - availableQuantity
        if (shortage <= 0) {
          return ''
        }
        return `${line.itemName}: faltam ${formatDecimal(shortage)} ${formatControlUnitShort(movementConfig.totalUnit)}`
      })
      .filter(Boolean)

    return shortages.join(' | ')
  }

  function notifyRequisitionStakeholders(record: RequisitionRecord, message: string) {
    if (currentCompanyId === null) {
      return
    }

    const recipientIds = Array.from(
      new Set([record.createdByUserId, record.approvedByUserId].filter((userId): userId is number => typeof userId === 'number')),
    ).filter((userId) => userId !== currentAppUser?.id)

    if (recipientIds.length === 0) {
      return
    }

    const now = new Date().toISOString()
    setRequisitionNotifications((current) => [
      ...recipientIds.map(
        (userId, index) =>
          ({
            id: Date.now() + index,
            companyId: currentCompanyId,
            userId,
            requisitionId: record.id,
            message,
            createdAt: now,
            isRead: false,
          }) satisfies RequisitionNotificationRecord,
      ),
      ...current,
    ])
  }

  function getLineDestinationCenter(line: RequisitionLineRecord) {
    if (line.destinationType !== 'PRODUCOES' || line.destinationCenterId === null) {
      return null
    }

    return stockCenters.find(
      (center) =>
        center.companyId === currentCompanyId &&
        center.isActive &&
        center.id === line.destinationCenterId,
    ) ?? null
  }

  function buildSplitRequisitionsForSending(record: RequisitionRecord) {
    const productionLines = record.lines.filter((line) => line.destinationType === 'PRODUCOES')
    const distributionLines = record.lines.filter((line) => line.destinationType === 'DISTRIBUICAO')
    const unresolvedProductionLines = productionLines.filter((line) => getLineDestinationCenter(line) === null)

    if (unresolvedProductionLines.length > 0) {
      return {
        error: `Existem pre-preparos sem centro produtor unico definido: ${unresolvedProductionLines
          .map((line) => line.itemName)
          .join(', ')}.`,
        requisitions: [] as RequisitionRecord[],
        remainingDistributionLines: distributionLines,
      }
    }

    const linesByDestination = new Map<number, RequisitionLineRecord[]>()
    productionLines.forEach((line) => {
      const centerId = line.destinationCenterId!
      linesByDestination.set(centerId, [...(linesByDestination.get(centerId) ?? []), line])
    })

    const now = new Date().toISOString()
    const splitRequisitions = Array.from(linesByDestination.entries()).map(([centerId, lines], index) => {
      const center = stockCenters.find((item) => item.id === centerId) ?? null
      const shouldReuseOriginalRecord = linesByDestination.size === 1 && distributionLines.length === 0
      return {
        ...record,
        id: shouldReuseOriginalRecord ? record.id : Date.now() + index + 1,
        supplyCenterId: centerId,
        supplyCenterName: center?.name ?? '',
        status: 'SENT_TO_SUPPLIES' as const,
        editScope: 'LINES_ONLY' as const,
        lines,
        sentAt: now,
        sentByUserId: currentAppUser?.id ?? null,
        sentByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        lastUpdatedAt: now,
        lastUpdatedByUserId: currentAppUser?.id ?? null,
        lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
      } satisfies RequisitionRecord
    })

    return {
      error: '',
      requisitions: splitRequisitions,
      remainingDistributionLines: distributionLines,
    }
  }

  function startEditRequisition(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (
      !targetRequisition ||
      !canManageRequisition(targetRequisition) ||
      targetRequisition.status === 'SENT_TO_SUPPLIES' ||
      targetRequisition.status === 'READY_TO_RECEIVE' ||
      targetRequisition.status === 'RECEIVED'
    ) {
      return
    }

    setRequisitionForm({ stockCenterId: String(targetRequisition.stockCenterId) })
    setEditingRequisitionId(targetRequisition.id)
    const center = stockCenters.find((item) => item.id === targetRequisition.stockCenterId) ?? null
    if (!center) {
      return
    }

    const savedLineByKey = new Map(targetRequisition.lines.map((line) => [line.key, line] as const))
    const nextDraftLines =
      targetRequisition.editScope === 'LINES_ONLY'
        ? targetRequisition.lines.map((line) => ({ ...line }))
        : (() => {
            const generatedLines = buildRequisitionDraftLines(center)
            const generatedLineKeys = new Set(generatedLines.map((line) => line.key))
            const mergedGeneratedLines = generatedLines.map((line) => {
              const savedLine = savedLineByKey.get(line.key) ?? null
              return savedLine
                ? {
                    ...line,
                    suggestedQuantity: savedLine.suggestedQuantity,
                    requestedQuantity: savedLine.requestedQuantity,
                  }
                : line
            })
            const savedOnlyLines = targetRequisition.lines
              .filter((line) => !generatedLineKeys.has(line.key))
              .map((line) => ({ ...line }))
            return [...savedOnlyLines, ...mergedGeneratedLines]
          })()
    setRequisitionDraftLines(nextDraftLines)
    setRequisitionDraftSearch('')
    setIsRequisitionEditModalOpen(true)
  }

  function closeRequisitionEditModal() {
    setIsRequisitionEditModalOpen(false)
    setEditingRequisitionId(null)
    setRequisitionDraftLines([])
    setRequisitionDraftSearch('')
  }

  function startSendRequisition(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (!targetRequisition || targetRequisition.status !== 'APPROVED') {
      return
    }

    const splitResult = buildSplitRequisitionsForSending(targetRequisition)
    if (splitResult.error) {
      setSaveFeedback({
        status: 'error',
        title: 'Destino de producao indefinido',
        message: splitResult.error,
      })
      return
    }
    if (splitResult.requisitions.length === 0 && splitResult.remainingDistributionLines.length === 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Nenhum pre-preparo para enviar',
        message: 'Esta requisicao nao possui pre-preparos com destino a centros produtores.',
      })
      return
    }

    confirmSendRequisition(requisitionId)
  }

  function approveRequisition(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (!targetRequisition || !canApproveRequisition(targetRequisition)) {
      return
    }

    setRequisitions((current) =>
      current.map((record) =>
        record.id === requisitionId && record.status === 'PENDING_APPROVAL'
          ? {
              ...record,
              status: 'APPROVED',
              approvedAt: new Date().toISOString(),
              approvedByUserId: currentAppUser?.id ?? null,
              approvedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
              lastUpdatedAt: new Date().toISOString(),
              lastUpdatedByUserId: currentAppUser?.id ?? null,
              lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
            }
          : record,
      ),
    )
    setSaveFeedback({
      status: 'success',
      title: 'Requisicao aprovada',
      message: 'A requisicao foi aprovada e pode ser exportada ou enviada para suprimentos.',
    })
  }

  function confirmSendRequisition(requisitionIdOverride?: number) {
    if (typeof requisitionIdOverride !== 'number') {
      return
    }
    const targetId = requisitionIdOverride

    const targetRequisition = requisitions.find((record) => record.id === targetId) ?? null
    if (!targetRequisition || targetRequisition.status !== 'APPROVED') {
      return
    }

    const splitResult = buildSplitRequisitionsForSending(targetRequisition)
    if (splitResult.error) {
      setSaveFeedback({
        status: 'error',
        title: 'Destino de producao indefinido',
        message: splitResult.error,
      })
      return
    }

    const now = new Date().toISOString()

    setRequisitions((current) => {
      const remainingRecords = current.filter((record) => record.id !== targetRequisition.id)
      const nextRecords = [...splitResult.requisitions]

      if (splitResult.remainingDistributionLines.length > 0) {
        nextRecords.push({
          ...targetRequisition,
          lines: splitResult.remainingDistributionLines,
          status: 'READY_TO_RECEIVE',
          editScope: 'LINES_ONLY',
          supplyCenterId: null,
          supplyCenterName: '',
          sentAt: now,
          sentByUserId: currentAppUser?.id ?? null,
          sentByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
          preparedAt: now,
          preparedByUserId: currentAppUser?.id ?? null,
          preparedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
          lastUpdatedAt: now,
          lastUpdatedByUserId: currentAppUser?.id ?? null,
          lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        })
      }

      return [...nextRecords, ...remainingRecords]
    })

    setSaveFeedback({
      status: 'success',
      title:
        splitResult.requisitions.length > 0 && splitResult.remainingDistributionLines.length > 0
          ? 'Requisicao desdobrada e enviada'
          : splitResult.requisitions.length > 0
            ? 'Requisicao enviada'
            : 'Requisicao enviada para receber',
      message:
        splitResult.requisitions.length > 0 && splitResult.remainingDistributionLines.length > 0
          ? 'Os pre-preparos foram enviados aos centros produtores e os itens de distribuicao permaneceram separados na requisicao.'
          : splitResult.requisitions.length > 0
            ? 'Os pre-preparos foram enviados automaticamente aos centros produtores correspondentes.'
            : 'Os itens de distribuicao foram enviados diretamente para receber, enquanto a integracao com o estoque central de distribuicao nao existe.',
    })
  }

  function startEditSupplyRequisition(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (!targetRequisition || !canManageSupplyRequisition(targetRequisition) || targetRequisition.status === 'RECEIVED') {
      return
    }

    setSupplyEditingRequisitionId(requisitionId)
    setSupplyDraftLines(targetRequisition.lines.map((line) => ({ ...line })))
    setSupplyDraftSearch('')
    setIsSupplyEditModalOpen(true)
  }

  function closeSupplyEditModal() {
    setSupplyEditingRequisitionId(null)
    setSupplyDraftLines([])
    setSupplyDraftSearch('')
    setIsSupplyEditModalOpen(false)
  }

  function openReceiveReviewRequisition(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (!targetRequisition || !canReceiveRequisition(targetRequisition)) {
      return
    }

    setReceiveReviewRequisitionId(requisitionId)
    setReceiveDraftLines(targetRequisition.lines.map((line) => ({ ...line })))
  }

  function requestCloseReceiveReviewRequisition() {
    if (receiveReviewRequisitionId === null) {
      return
    }
    setIsReceiveReviewDiscardConfirmOpen(true)
  }

  function closeReceiveReviewRequisition() {
    setReceiveReviewRequisitionId(null)
    setReceiveDraftLines([])
    setIsReceiveReviewDiscardConfirmOpen(false)
  }

  function finalizeRequisitionIfAllLinesResolved(
    requisition: RequisitionRecord,
    updatedLines: RequisitionLineRecord[],
    resolvedAt: string,
  ) {
    const allResolved = updatedLines.every((line) => line.receiptStatus === 'RECEIVED' || line.receiptStatus === 'NOT_RECEIVED')
    return allResolved
      ? {
          ...requisition,
          status: 'RECEIVED' as const,
          lines: updatedLines,
          receivedAt: resolvedAt,
          receivedByUserId: currentAppUser?.id ?? null,
          receivedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
          lastUpdatedAt: resolvedAt,
          lastUpdatedByUserId: currentAppUser?.id ?? null,
          lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        }
      : {
          ...requisition,
          status: 'READY_TO_RECEIVE' as const,
          lines: updatedLines,
          lastUpdatedAt: resolvedAt,
          lastUpdatedByUserId: currentAppUser?.id ?? null,
          lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        }
  }

  function saveSupplyDraft() {
    if (supplyEditingRequisitionId === null) {
      return
    }

    const targetRequisition = requisitions.find((record) => record.id === supplyEditingRequisitionId) ?? null
    if (!targetRequisition || !canManageSupplyRequisition(targetRequisition)) {
      return
    }

    const linesToSave = supplyDraftLines.filter((line) => (parseDecimal(line.requestedQuantity) ?? 0) > 0)
    const now = new Date().toISOString()
    setRequisitions((current) =>
      current.map((record) =>
        record.id === supplyEditingRequisitionId
          ? {
              ...record,
              lines: linesToSave,
              lastUpdatedAt: now,
              lastUpdatedByUserId: currentAppUser?.id ?? null,
              lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
            }
          : record,
      ),
    )

    notifyRequisitionStakeholders(
      targetRequisition,
      `A REQUISICAO DO CENTRO ${targetRequisition.stockCenterName} FOI EDITADA EM SUPRIMENTOS.`,
    )

    closeSupplyEditModal()
    setSaveFeedback({
      status: 'success',
      title: 'Requisicao atualizada em suprimentos',
      message: 'A lista separada foi atualizada e os envolvidos foram notificados.',
    })
  }

  function cancelSupplyRequisition(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (!targetRequisition || !canManageSupplyRequisition(targetRequisition)) {
      return
    }

    const now = new Date().toISOString()
    setRequisitions((current) =>
      current.map((record) =>
        record.id === requisitionId
          ? {
              ...record,
              status: 'PENDING_APPROVAL',
              editScope: 'FULL',
              supplyCenterId: null,
              supplyCenterName: '',
              approvedAt: '',
              approvedByUserId: null,
              approvedByUserName: '',
              sentAt: '',
              sentByUserId: null,
              sentByUserName: '',
              preparedAt: '',
              preparedByUserId: null,
              preparedByUserName: '',
              lastUpdatedAt: now,
              lastUpdatedByUserId: currentAppUser?.id ?? null,
              lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
            }
          : record,
      ),
    )

    notifyRequisitionStakeholders(
      targetRequisition,
      `A REQUISICAO DO CENTRO ${targetRequisition.stockCenterName} FOI DEVOLVIDA DE SUPRIMENTOS PARA NOVA APROVACAO.`,
    )

    setSaveFeedback({
      status: 'success',
      title: 'Requisicao devolvida para pendente',
      message: 'A requisicao saiu de suprimentos e voltou para o status pendente de aprovacao.',
    })
  }

  function registerOperationalInventoryMovement(
    stockCenterId: number,
    description: string,
    session: InventoryCountSessionRecord,
    records: InventoryCountRecord[],
  ) {
    const openInventory =
      inventoryRecords.find(
        (inventoryRecord) =>
          inventoryRecord.companyId === currentCompanyId &&
          inventoryRecord.stockCenterId === stockCenterId &&
          !inventoryRecord.isClosed,
      ) ?? null

    if (!openInventory) {
      setInventoryCountSessions((current) => [session, ...current])
      setInventoryCounts((current) => [...records, ...current])
      return 'applied' as const
    }

    setPendingInventoryMovements((current) => [
      {
        id: Date.now() + current.length,
        companyId: currentCompanyId ?? 0,
        stockCenterId,
        inventoryId: openInventory.id,
        createdAt: new Date().toISOString(),
        createdByUserId: currentAppUser?.id ?? null,
        createdByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        description,
        session,
        records,
      },
      ...current,
    ])
    return 'queued' as const
  }

  function moveRequisitionToReceive(requisitionId: number) {
    const targetRequisition = requisitions.find((record) => record.id === requisitionId) ?? null
    if (!targetRequisition || !canManageSupplyRequisition(targetRequisition) || currentCompanyId === null) {
      return
    }

    const shortageMessage = getSupplyRequisitionStockShortageMessage(targetRequisition)
    if (shortageMessage) {
      setSaveFeedback({
        status: 'error',
        title: 'Estoque insuficiente para mover requisicao',
        message: `O centro de suprimentos ainda nao possui saldo suficiente para esta separacao. ${shortageMessage}`,
      })
      return
    }

    const sourceCenterId = targetRequisition.supplyCenterId
    const sourceCenterName = targetRequisition.supplyCenterName
    const shouldDeductSourceInventory = typeof sourceCenterId === 'number' && sourceCenterId > 0
    const countedAt = shouldDeductSourceInventory
      ? latestInventoryDateByCenterId.get(sourceCenterId) ?? getTodayDateInputValue()
      : getTodayDateInputValue()
    const movementTimestamp = Date.now()
    const now = new Date().toISOString()

    if (shouldDeductSourceInventory) {
      const sourceSession: InventoryCountSessionRecord = {
        id: movementTimestamp,
        inventoryId: null,
        companyId: currentCompanyId,
        stockCenterId: sourceCenterId,
        countedAt,
        isClosed: true,
        startedAt: now,
        startedByUserId: currentAppUser?.id ?? null,
        startedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        closedAt: now,
        closedByUserId: currentAppUser?.id ?? null,
        closedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
      }

      const sourceMovementRecords: InventoryCountRecord[] = targetRequisition.lines.map((line, index) => ({
          id: movementTimestamp + index + 1,
          inventoryId: null,
          sessionId: movementTimestamp,
          companyId: currentCompanyId,
          stockCenterId: sourceCenterId,
          countedAt,
          storageLocation: 'SAIDA PARA REQUISICAO',
          technicalSheetId: line.kind === 'PREPARO' ? line.technicalSheetId : null,
          productId: line.kind === 'PRODUTO' ? line.productId : '',
          serviceItemId: line.kind === 'ITEM' ? line.serviceItemId : '',
          packageId: line.kind === 'PRODUTO' || line.kind === 'ITEM' ? line.packageId : null,
          technicalSheetName: line.itemName,
          technicalSheetKind: line.kind,
          recipientItemId: '',
          recipientLabel: `MOVIDO PARA ${targetRequisition.stockCenterName}`,
          closedItemsQuantity: formatDecimal(-((parseDecimal(line.requestedQuantity) ?? 0) * getRequisitionStockMovementConfig(line).multiplier)),
          hasOpenItems: false,
          openItemsGrossWeight: '',
          openItemsContainerQuantity: '',
          openItemsNetQuantity: '',
          totalCountedQuantity: formatDecimal(-((parseDecimal(line.requestedQuantity) ?? 0) * getRequisitionStockMovementConfig(line).multiplier)),
          totalCountedUnit: getRequisitionStockMovementConfig(line).totalUnit,
          createdByUserId: currentAppUser?.id ?? null,
          createdByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
        }))
      const sourceMovementResult = registerOperationalInventoryMovement(
        sourceCenterId,
        `SAIDA PARA REQUISICAO • ${targetRequisition.stockCenterName}`,
        sourceSession,
        sourceMovementRecords,
      )
      if (sourceMovementResult === 'queued') {
        setSaveFeedback({
          status: 'success',
          title: 'Requisicao pronta para recebimento',
          message:
            `O centro ${sourceCenterName} esta com inventario aberto. A baixa de estoque foi registrada como pendente e sera aplicada quando esse inventario for finalizado.`,
        })
      }
    }

    setRequisitions((current) =>
      current.map((record) =>
        record.id === requisitionId
          ? {
              ...record,
              status: 'READY_TO_RECEIVE',
              preparedAt: now,
              preparedByUserId: currentAppUser?.id ?? null,
              preparedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
              lastUpdatedAt: now,
              lastUpdatedByUserId: currentAppUser?.id ?? null,
              lastUpdatedByUserName: currentAppUser?.fullName ?? 'Administrador do sistema',
            }
          : record,
      ),
    )

    if (!(shouldDeductSourceInventory && inventoryRecords.some((inventoryRecord) => inventoryRecord.companyId === currentCompanyId && inventoryRecord.stockCenterId === sourceCenterId && !inventoryRecord.isClosed))) {
      setSaveFeedback({
        status: 'success',
        title: 'Requisicao pronta para recebimento',
        message: shouldDeductSourceInventory
          ? `A requisicao foi movida para receber no centro solicitante e o estoque do centro ${sourceCenterName} foi baixado.`
          : 'A requisicao foi movida para receber no centro solicitante.',
      })
    }
  }

