  function saveInventorySummaryDraft(recordId: number) {
    if (
      currentCompanyId === null ||
      !selectedInventoryRecord ||
      selectedInventoryRecord.isClosed ||
      !canEditInventorySummary
    ) {
      return
    }

    try {
      const nextRecords = inventoryCounts.map((record) => {
        if (
          record.companyId !== currentCompanyId ||
          record.inventoryId !== selectedInventoryRecord.id ||
          record.id !== recordId
        ) {
          return record
        }

        const draft = inventorySummaryDrafts[`record-${record.id}`]
        if (!draft) {
          return record
        }

        const countableItem =
          record.technicalSheetKind === 'PREPARO'
            ? inventoryCountableItems.find((item) => item.kind === 'PREPARO' && item.technicalSheetId === record.technicalSheetId) ?? null
            : record.technicalSheetKind === 'PRODUTO'
              ? inventoryCountableItems.find((item) => item.kind === 'PRODUTO' && item.productId === record.productId) ?? null
              : inventoryCountableItems.find((item) => item.kind === 'ITEM' && item.serviceItemId === record.serviceItemId) ?? null
        const sheet =
          record.technicalSheetKind === 'PREPARO' && record.technicalSheetId !== null
            ? inventoryCountableSheets.find((item) => item.id === record.technicalSheetId) ?? null
            : null
        const product = record.technicalSheetKind === 'PRODUTO' ? productById.get(record.productId) ?? null : null
        const serviceItem = record.technicalSheetKind === 'ITEM' ? serviceItemsById.get(record.serviceItemId) ?? null : null
        const recipientOptions = buildInventoryRecipientOptionsForContext({
          countableItem,
          sheet,
          product,
          serviceItem,
          serviceItemsById,
        })
        const selectedRecipient = recipientOptions.find((item) => item.id === draft.recipientItemId) ?? null
        const hasRecipientOptions = recipientOptions.length > 0
        const hasOpenItems = draft.hasOpenItems === 'true'

        if (!countableItem) {
          throw new Error(`Nao foi possivel identificar o item ${record.technicalSheetName} para atualizar o inventario.`)
        }

        if (!draft.storageLocation.trim()) {
          throw new Error(`Informe o local de armazenamento para ${record.technicalSheetName}.`)
        }

        if (record.technicalSheetKind === 'PRODUTO' && !selectedRecipient) {
          throw new Error(`Selecione uma embalagem valida para ${record.technicalSheetName}.`)
        }

        if (record.technicalSheetKind === 'ITEM' && !selectedRecipient) {
          throw new Error(`Selecione unidade ou uma embalagem valida para ${record.technicalSheetName}.`)
        }

        if (record.technicalSheetKind === 'PREPARO' && hasRecipientOptions && !selectedRecipient) {
          throw new Error(`Selecione um recipiente valido para ${record.technicalSheetName}.`)
        }

        if ((parseDecimal(draft.closedItemsQuantity) ?? 0) < 0) {
          throw new Error(`Informe uma quantidade valida de itens fechados para ${record.technicalSheetName}.`)
        }

        if (hasOpenItems) {
          if (countableItem.kind === 'ITEM' || countableItem.controlUnit === 'UNIT') {
            throw new Error(`Itens abertos nao se aplicam a ${record.technicalSheetName}.`)
          }
          if (!hasRecipientOptions || !selectedRecipient) {
            throw new Error(`Selecione um recipiente valido para declarar itens abertos em ${record.technicalSheetName}.`)
          }
          if ((parseDecimal(draft.openItemsGrossWeight) ?? 0) <= 0) {
            throw new Error(`Informe o peso total dos itens abertos para ${record.technicalSheetName}.`)
          }
          if ((parseDecimal(draft.openItemsContainerQuantity) ?? 0) <= 0) {
            throw new Error(`Informe quantos itens abertos foram pesados para ${record.technicalSheetName}.`)
          }
        }

        const densityFactor = getInventoryDensityFactorForContext({ countableItem, product, sheet })
        const openPhysicalQuantity = calculateInventoryOpenPhysicalQuantityForContext({
          countableItem,
          hasOpenItems,
          openItemsGrossWeight: draft.openItemsGrossWeight,
          openItemsContainerQuantity: draft.openItemsContainerQuantity,
          recipient: selectedRecipient,
          densityFactor,
        })
        const totalCountedQuantity = calculateInventoryTotalCountedQuantityForContext({
          countableItem,
          sheet,
          hasRecipientOptions,
          recipient: selectedRecipient,
          closedItemsQuantity: draft.closedItemsQuantity,
          hasOpenItems,
          openPhysicalQuantity,
        })
        const totalCountedUnit: InventoryCountRecord['totalCountedUnit'] =
          countableItem.kind === 'ITEM'
            ? 'UNIT'
            : countableItem.controlUnit === 'GRAM'
              ? 'GRAM'
              : countableItem.controlUnit === 'UNIT'
                ? 'UNIT'
                : 'MILLILITER'

        return {
          ...record,
          storageLocation: normalizeRegistrationText(draft.storageLocation),
          recipientItemId: selectedRecipient?.id ?? '',
          recipientLabel: selectedRecipient?.label ?? 'SEM RECIPIENTE VINCULADO',
          packageId:
            countableItem.kind === 'PRODUTO' || countableItem.kind === 'ITEM'
              ? selectedRecipient?.packageId ?? null
              : null,
          closedItemsQuantity: draft.closedItemsQuantity || '0',
          hasOpenItems,
          openItemsGrossWeight: hasOpenItems ? draft.openItemsGrossWeight : '',
          openItemsContainerQuantity: hasOpenItems ? draft.openItemsContainerQuantity : '',
          openItemsNetQuantity: hasOpenItems ? formatDecimal(openPhysicalQuantity) : '',
          totalCountedQuantity: formatDecimal(totalCountedQuantity),
          totalCountedUnit,
        }
      })

      setInventoryCounts(nextRecords)
      setInventorySummaryEditingRowKey(null)
      setSaveFeedback({
        status: 'success',
        title: 'Resumo do inventario atualizado',
        message: 'O item foi atualizado diretamente no resumo do inventario.',
      })
    } catch (error) {
      setSaveFeedback({
        status: 'error',
        title: 'Nao foi possivel atualizar o resumo do inventario',
        message: error instanceof Error ? error.message : 'Revise os valores informados e tente novamente.',
      })
    }
  }

