  function updateProductForm<K extends keyof ProductFormState>(field: K, value: ProductFormState[K]) {
    if (field === 'companyProductId' || field === 'name' || field === 'family' || field === 'subfamily') {
      setProductForm((current) => ({
        ...current,
        [field]: normalizeRegistrationText(String(value)) as ProductFormState[K],
      }))
      return
    }

    if (field === 'sectors') {
      setProductForm((current) => ({
        ...current,
        sectors: (value as string[]).map((item) => normalizeRegistrationText(item)).filter(Boolean),
      }))
      return
    }

    setProductForm((current) => ({ ...current, [field]: value }))
  }

  async function saveProduct() {
    if (isSavingProduct) {
      return
    }

    const previousProduct = editingProductId ? products.find((product) => product.id === editingProductId) ?? null : null
    const normalizedName = normalizeRegistrationText(productForm.name.trim())
    const normalizedFamily = normalizeRegistrationText(productForm.family.trim())
    const normalizedSubfamily = normalizeRegistrationText(productForm.subfamily.trim())
    const normalizedSectors = productForm.sectors
      .map((sector) => normalizeRegistrationText(sector.trim()))
      .filter(Boolean)

    const errors: string[] = []

    if (!normalizedName) {
      errors.push('nome do produto obrigatorio')
    }
    if (!productForm.controlUnit) {
      errors.push('unidade de controle obrigatoria')
    }
    if (!normalizedFamily) {
      errors.push('familia obrigatoria')
    }
    if (!normalizedSubfamily) {
      errors.push('subfamilia obrigatoria')
    }
    if (normalizedSectors.length === 0) {
      errors.push('ao menos 1 setor obrigatorio')
    }
    if (technicalSheetDraftStack.length > 0 && packages.length === 0) {
      errors.push('cadastre ao menos 1 embalagem para usar este produto na ficha tecnica')
    }

    if (errors.length > 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar produto',
        message: `Erro: ${errors.join('; ')}.`,
      })
      return
    }

    const normalizedNameKey = buildNormalizedRegistrationNameKey(normalizedName)
    const duplicateProduct = products.find(
      (product) =>
        product.companyId === (currentCompanyId ?? 0) &&
        product.id !== editingProductId &&
        buildNormalizedRegistrationNameKey(product.name) === normalizedNameKey,
    )
    if (duplicateProduct) {
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar produto',
        message: `Ja existe um produto cadastrado com o nome ${normalizedName}.`,
      })
      return
    }

    const productToSave: ProductRecord = {
      companyId: currentCompanyId ?? 0,
      id: previousProduct?.id ?? generatedProductId,
      companyProductId: normalizeRegistrationText(productForm.companyProductId.trim()),
      name: normalizedName,
      controlUnit: productForm.controlUnit,
      family: normalizedFamily,
      subfamily: normalizedSubfamily,
      sectors: normalizedSectors,
      alcoholPercentage: productForm.alcoholPercentage.trim(),
      densitySampleVolume: productForm.densitySampleVolume.trim(),
      densitySampleWeight: productForm.densitySampleWeight.trim(),
      ignoreStock: productForm.ignoreStock,
      isActive: hasPackages,
      packages,
    }

    const nextProducts = editingProductId
      ? products.map((product) => (product.id === editingProductId ? { ...product, ...productToSave } : product))
      : [productToSave, ...products]

    let nextTechnicalSheets = technicalSheets
    if (previousProduct) {
      const syncedSheets = syncTechnicalSheetIngredientReferences(
        technicalSheets,
        previousProduct.id,
        productToSave.id,
        productToSave.name,
      )

      nextTechnicalSheets =
        typeof previousProduct.technicalSheetId !== 'number'
          ? syncedSheets
          : syncedSheets.map((sheet) =>
              sheet.id === previousProduct.technicalSheetId
                ? {
                    ...sheet,
                    productId: productToSave.id,
                    companyProductId: productToSave.companyProductId,
                    name: productToSave.name,
                    family: productToSave.family,
                    subfamily: productToSave.subfamily,
                    sectors: productToSave.sectors,
                    outputUnit: productToSave.controlUnit,
                    densitySampleVolume: productToSave.densitySampleVolume,
                    densitySampleWeight: productToSave.densitySampleWeight,
                  }
                : sheet,
            )
    }

    setIsSavingProduct(true)
    setSaveProgressState({
      title: 'Registrando produto',
      message: 'Registrando, aguarde. Nao feche a tela nem clique novamente em salvar.',
    })
    try {
      await upsertProductRecordOnApi(productToSave, editingProductId)
      await persistChangedTechnicalSheetsOnApi(technicalSheets, nextTechnicalSheets)
    } catch (error) {
      console.error(error)
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar produto',
        message: error instanceof Error ? error.message : 'Erro ao salvar produto no servidor.',
      })
      return
    } finally {
      setIsSavingProduct(false)
      setSaveProgressState(null)
    }

    setProducts(nextProducts)
    setTechnicalSheets(nextTechnicalSheets)
    await refreshAppCatalogRecordsFromApi()

    if (restoreTechnicalSheetDraftWithCreatedIngredient(productToSave.id, productToSave.name)) {
      setIsTechnicalSheetProductModalOpen(false)
    }

    setSaveFeedback({
      status: 'success',
      title: 'Produto salvo com sucesso',
      message: hasPackages
        ? 'O produto foi salvo e ja esta apto para uso operacional porque possui apresentacao cadastrada.'
        : 'O produto foi salvo como rascunho. Cadastre ao menos uma apresentacao para liberar uso e contagem.',
    })
  }

