  function openEditTechnicalSheetForm(technicalSheetId: number) {
    const technicalSheet = technicalSheets.find((item) => item.id === technicalSheetId)
    if (!technicalSheet) {
      return
    }

    const nextForm = {
      kind: technicalSheet.kind ?? 'PREPARO',
      companyProductId: technicalSheet.companyProductId,
      name: technicalSheet.name,
      family: technicalSheet.family,
      subfamily: technicalSheet.subfamily,
      sectors: technicalSheet.sectors,
      outputQuantity: technicalSheet.outputQuantity,
      outputUnit: technicalSheet.outputUnit,
      densitySampleVolume: technicalSheet.densitySampleVolume || '',
      densitySampleWeight: technicalSheet.densitySampleWeight || '',
      yieldDifferenceDestination: technicalSheet.yieldDifferenceDestination || '',
      yieldDifferenceByproductName: technicalSheet.yieldDifferenceByproductName || '',
      yieldDifferenceByproductTechnicalSheetId: technicalSheet.yieldDifferenceByproductTechnicalSheetId ?? null,
      targetPh: technicalSheet.targetPh || '',
      targetBrix: technicalSheet.targetBrix || '',
      portionSize: technicalSheet.portionSize || '1000',
      colorTagOne: technicalSheet.colorTagOne || '',
      colorTagTwo: technicalSheet.colorTagTwo || '',
      desiredCmvPercentage: technicalSheet.desiredCmvPercentage || '',
      dilutionRatePercentage: technicalSheet.dilutionRatePercentage || '',
      imageDataUrl: technicalSheet.imageDataUrl || '',
      finalSalePrice: technicalSheet.finalSalePrice || '',
      flavorSweet: technicalSheet.flavorSweet || '0',
      flavorSour: technicalSheet.flavorSour || '0',
      flavorBitter: technicalSheet.flavorBitter || '0',
      flavorSalty: technicalSheet.flavorSalty || '0',
      flavorUmami: technicalSheet.flavorUmami || '0',
      storytelling: technicalSheet.storytelling || '',
      preparationMode: technicalSheet.preparationMode,
      shelfLifeRoom: technicalSheet.shelfLifeRoom,
      shelfLifeRefrigerated: technicalSheet.shelfLifeRefrigerated,
      shelfLifeFrozen: technicalSheet.shelfLifeFrozen,
      productionCenters: technicalSheet.productionCenters ?? [],
    } satisfies TechnicalSheetFormState
    setActiveSection('FichasTecnicas')
    setTechnicalSheetScreenMode('form')
    setTechnicalSheetDraftStack([])
    setPendingNestedTechnicalSheetKind(null)
    setPendingNestedTechnicalSheetPurpose(null)
    setDraftTechnicalSheetProductId(technicalSheet.productId)
    setEditingTechnicalSheetId(technicalSheetId)
    setTechnicalSheetSectorInput('')
    setTechnicalSheetForm(nextForm)
    const savedIngredients =
      technicalSheet.ingredients.length > 0
        ? technicalSheet.ingredients.map((ingredient) => ({
            ...ingredient,
            productLabel:
              products.find((product) => product.id === ingredient.productId)?.name ?? ingredient.productLabel ?? '',
          }))
        : []
    const nextIngredient = emptyTechnicalSheetIngredient()
    setTechnicalSheetIngredients([...savedIngredients, nextIngredient])
    setEditingTechnicalSheetIngredientId(nextIngredient.id)
    const savedGarnishIngredients =
      technicalSheet.garnishIngredients.length > 0
        ? technicalSheet.garnishIngredients.map((ingredient) => ({
            ...ingredient,
            productLabel:
              products.find((product) => product.id === ingredient.productId)?.name ?? ingredient.productLabel ?? '',
          }))
        : []
    const nextGarnishIngredient = emptyTechnicalSheetIngredient()
    setTechnicalSheetGarnishIngredients([...savedGarnishIngredients, nextGarnishIngredient])
    setEditingTechnicalSheetGarnishIngredientId(technicalSheet.kind === 'EXECUCAO' ? nextGarnishIngredient.id : null)
    const savedServiceItems =
      technicalSheet.serviceItems.length > 0
        ? technicalSheet.serviceItems.map((serviceItem) => ({
            ...serviceItem,
            itemLabel: serviceItems.find((item) => item.id === serviceItem.itemId)?.name ?? serviceItem.itemLabel ?? '',
          }))
        : []
    const nextServiceItem = emptyTechnicalSheetServiceItem()
    setTechnicalSheetServiceItems([...savedServiceItems, nextServiceItem])
    setEditingTechnicalSheetServiceItemId(technicalSheet.kind === 'EXECUCAO' ? nextServiceItem.id : null)
    const linkedTechnicalSheetProduct =
      products.find((product) => product.technicalSheetId === technicalSheetId && product.companyId === currentCompanyId) ?? null
    const savedSuggestedYield = calculateTechnicalSheetSuggestedYieldFromDraft(
      technicalSheet.kind,
      savedIngredients,
      savedGarnishIngredients,
    )
    const savedOutputQuantity = parseDecimal(technicalSheet.outputQuantity) ?? 0
    setTechnicalSheetPackages(linkedTechnicalSheetProduct?.packages ?? [])
    setPackageEditorContext('technicalSheet')
    setTechnicalSheetOutputQuantityMode(
      technicalSheet.kind === 'PREPARO' && (savedOutputQuantity <= 0 || Math.abs(savedOutputQuantity - savedSuggestedYield) < 0.000001)
        ? 'auto'
        : 'manual',
    )
    setTechnicalSheetDiscardBaseline(
      buildTechnicalSheetDiscardSnapshot({
        form: nextForm,
        sectorInput: '',
        productionCenterInput: '',
        ingredients: [...savedIngredients, nextIngredient],
        garnishIngredients: [...savedGarnishIngredients, nextGarnishIngredient],
        serviceItems: [...savedServiceItems, nextServiceItem],
        packages: linkedTechnicalSheetProduct?.packages ?? [],
        editingId: technicalSheetId,
      }),
    )
  }

  function updateTechnicalSheetForm<K extends keyof TechnicalSheetFormState>(
    field: K,
    value: TechnicalSheetFormState[K],
  ) {
    if (field === 'kind') {
      const nextKind = value as TechnicalSheetKind
    setTechnicalSheetForm((current) => ({
        ...current,
        kind: nextKind,
        outputUnit:
          nextKind === 'EXECUCAO'
            ? current.outputUnit === 'UNIT' || current.outputUnit === 'COMBO'
              ? current.outputUnit
              : 'UNIT'
            : nextKind === 'VENDA'
              ? current.outputUnit === 'UNIT' || current.outputUnit === 'COMBO'
                ? current.outputUnit
                : 'UNIT'
              : current.outputUnit === 'MILLILITER' || current.outputUnit === 'GRAM' || current.outputUnit === 'UNIT'
                ? current.outputUnit
                : 'GRAM',
        portionSize: isCommercialTechnicalSheetKind(nextKind) ? '1' : current.portionSize === '1' ? '1000' : current.portionSize,
        densitySampleVolume: isCommercialTechnicalSheetKind(nextKind) ? '' : current.densitySampleVolume,
        densitySampleWeight: isCommercialTechnicalSheetKind(nextKind) ? '' : current.densitySampleWeight,
        targetPh: nextKind === 'PREPARO' ? current.targetPh : '',
        targetBrix: nextKind === 'PREPARO' ? current.targetBrix : '',
        colorTagOne: nextKind === 'PREPARO' ? current.colorTagOne : '',
        colorTagTwo: nextKind === 'PREPARO' ? current.colorTagTwo : '',
        desiredCmvPercentage: isCommercialTechnicalSheetKind(nextKind) ? current.desiredCmvPercentage : '',
        dilutionRatePercentage: nextKind === 'EXECUCAO' ? current.dilutionRatePercentage : '',
        imageDataUrl: nextKind === 'EXECUCAO' ? current.imageDataUrl : '',
        finalSalePrice: isCommercialTechnicalSheetKind(nextKind) ? current.finalSalePrice : '',
        flavorSweet: nextKind === 'EXECUCAO' ? current.flavorSweet : '0',
        flavorSour: nextKind === 'EXECUCAO' ? current.flavorSour : '0',
        flavorBitter: nextKind === 'EXECUCAO' ? current.flavorBitter : '0',
        flavorSalty: nextKind === 'EXECUCAO' ? current.flavorSalty : '0',
        flavorUmami: nextKind === 'EXECUCAO' ? current.flavorUmami : '0',
        storytelling: nextKind === 'EXECUCAO' ? current.storytelling : '',
        preparationMode: nextKind === 'VENDA' ? '' : current.preparationMode,
        shelfLifeRoom: isCommercialTechnicalSheetKind(nextKind) ? '' : current.shelfLifeRoom,
        shelfLifeRefrigerated: isCommercialTechnicalSheetKind(nextKind) ? '' : current.shelfLifeRefrigerated,
        shelfLifeFrozen: isCommercialTechnicalSheetKind(nextKind) ? '' : current.shelfLifeFrozen,
      }))
      if (isCommercialTechnicalSheetKind(nextKind)) {
        setTechnicalSheetPackages([])
      }
      if (nextKind === 'EXECUCAO') {
        const nextGarnishIngredient = emptyTechnicalSheetIngredient()
        setTechnicalSheetGarnishIngredients((current) =>
          current.some(
            (ingredient) =>
              ingredient.productLabel.trim() !== '' ||
              ingredient.quantity.trim() !== '' ||
              ingredient.yieldQuantity.trim() !== '' ||
              ingredient.productId.trim() !== '',
          )
            ? current
            : [nextGarnishIngredient],
        )
        setEditingTechnicalSheetGarnishIngredientId((current) => current ?? nextGarnishIngredient.id)
        const nextServiceItem = emptyTechnicalSheetServiceItem()
        setTechnicalSheetServiceItems((current) =>
          current.some((item) => item.itemLabel.trim() !== '' || item.quantity.trim() !== '' || item.itemId.trim() !== '')
            ? current
            : [nextServiceItem],
        )
        setEditingTechnicalSheetServiceItemId((current) => current ?? nextServiceItem.id)
      } else {
        setTechnicalSheetGarnishIngredients([emptyTechnicalSheetIngredient()])
        setEditingTechnicalSheetGarnishIngredientId(null)
        setTechnicalSheetServiceItems([emptyTechnicalSheetServiceItem()])
        setEditingTechnicalSheetServiceItemId(null)
      }
      return
    }

    if (field === 'name' || field === 'family' || field === 'subfamily' || field === 'companyProductId') {
      setTechnicalSheetForm((current) => ({
        ...current,
        [field]: normalizeRegistrationText(String(value)) as TechnicalSheetFormState[K],
      }))
      return
    }

    if (field === 'sectors') {
      setTechnicalSheetForm((current) => ({
        ...current,
        sectors: (value as string[]).map((item) => normalizeRegistrationText(item)).filter(Boolean),
      }))
      return
    }

    if (field === 'yieldDifferenceDestination') {
      const destination = value as TechnicalSheetYieldDifferenceDestination
      setTechnicalSheetForm((current) => ({
        ...current,
        yieldDifferenceDestination: destination,
        yieldDifferenceByproductName: destination === 'BYPRODUCT' ? current.yieldDifferenceByproductName : '',
        yieldDifferenceByproductTechnicalSheetId:
          destination === 'BYPRODUCT' ? current.yieldDifferenceByproductTechnicalSheetId : null,
      }))
      return
    }

    if (field === 'outputQuantity') {
      const nextValue = String(value)
      setTechnicalSheetOutputQuantityMode(nextValue.trim() === '' ? 'auto' : 'manual')
      setTechnicalSheetForm((current) => ({ ...current, outputQuantity: nextValue }))
      return
    }

    if (
      field === 'preparationMode' ||
      field === 'storytelling' ||
      field === 'shelfLifeRoom' ||
      field === 'shelfLifeRefrigerated' ||
      field === 'shelfLifeFrozen'
    ) {
      setTechnicalSheetForm((current) => ({
        ...current,
        [field]:
          (field === 'preparationMode' || field === 'storytelling'
            ? normalizeFreeText(String(value))
            : normalizeRegistrationText(String(value))) as TechnicalSheetFormState[K],
      }))
      return
    }

    setTechnicalSheetForm((current) => ({ ...current, [field]: value }))
  }

  function updateTechnicalSheetImage(file: File | null) {
    if (!file || !file.type.startsWith('image/')) {
      return
    }

    const reader = new FileReader()
    reader.onload = () => {
      const result = typeof reader.result === 'string' ? reader.result : ''
      setTechnicalSheetForm((current) => ({
        ...current,
        imageDataUrl: result,
      }))
    }
    reader.readAsDataURL(file)
  }

