  function isTechnicalSheetIngredientComplete(ingredient: TechnicalSheetIngredient) {
    return ingredient.productId.trim() !== '' && ingredient.quantity.trim() !== '' && ingredient.yieldQuantity.trim() !== ''
  }

  function isTechnicalSheetServiceItemComplete(serviceItem: TechnicalSheetServiceItem) {
    return serviceItem.itemId.trim() !== '' && serviceItem.quantity.trim() !== ''
  }

  function handleTechnicalSheetIngredientEnter(
    event: KeyboardEvent<HTMLInputElement>,
    ingredientId: number,
  ) {
    if (event.key !== 'Enter') {
      return
    }

    event.preventDefault()
    const currentIngredient = technicalSheetIngredients.find((ingredient) => ingredient.id === ingredientId)
    if (!currentIngredient) {
      return
    }

    if (
      event.currentTarget instanceof HTMLInputElement &&
      event.currentTarget.list?.id === technicalSheetProductListId &&
      currentIngredient.productId.trim() === '' &&
      currentIngredient.productLabel.trim() !== ''
    ) {
      openNewProductFormFromTechnicalSheet(ingredientId, currentIngredient.productLabel)
      return
    }

    if (!isTechnicalSheetIngredientComplete(currentIngredient)) {
      return
    }

    const isLastRow = technicalSheetIngredients[technicalSheetIngredients.length - 1]?.id === ingredientId
    if (isLastRow) {
      addTechnicalSheetIngredient()
      return
    }

    setEditingTechnicalSheetIngredientId(null)
  }

  function openTechnicalSheetIngredientProductModal(ingredientId: number) {
    const currentIngredient = technicalSheetIngredients.find((ingredient) => ingredient.id === ingredientId) ?? null
    if (!currentIngredient || currentIngredient.productId.trim() !== '' || currentIngredient.productLabel.trim() === '') {
      return
    }

    openNewProductFormFromTechnicalSheet(ingredientId, currentIngredient.productLabel)
  }

  function handleTechnicalSheetGarnishIngredientEnter(
    event: KeyboardEvent<HTMLInputElement>,
    ingredientId: number,
  ) {
    if (event.key !== 'Enter') {
      return
    }

    event.preventDefault()
    const currentIngredient = technicalSheetGarnishIngredients.find((ingredient) => ingredient.id === ingredientId)
    if (!currentIngredient) {
      return
    }

    if (
      event.currentTarget instanceof HTMLInputElement &&
      event.currentTarget.list?.id === technicalSheetProductListId &&
      currentIngredient.productId.trim() === '' &&
      currentIngredient.productLabel.trim() !== ''
    ) {
      openNewProductFormFromTechnicalSheetGarnish(ingredientId, currentIngredient.productLabel)
      return
    }

    if (!isTechnicalSheetIngredientComplete(currentIngredient)) {
      return
    }

    const isLastRow = technicalSheetGarnishIngredients[technicalSheetGarnishIngredients.length - 1]?.id === ingredientId
    if (isLastRow) {
      addTechnicalSheetGarnishIngredient()
      return
    }

    setEditingTechnicalSheetGarnishIngredientId(null)
  }

  function openTechnicalSheetGarnishIngredientProductModal(ingredientId: number) {
    const currentIngredient = technicalSheetGarnishIngredients.find((ingredient) => ingredient.id === ingredientId) ?? null
    if (!currentIngredient || currentIngredient.productId.trim() !== '' || currentIngredient.productLabel.trim() === '') {
      return
    }

    openNewProductFormFromTechnicalSheetGarnish(ingredientId, currentIngredient.productLabel)
  }

  function handleTechnicalSheetServiceItemEnter(
    event: KeyboardEvent<HTMLInputElement>,
    serviceItemId: number,
  ) {
    if (event.key !== 'Enter') {
      return
    }

    event.preventDefault()
    const currentItem = technicalSheetServiceItems.find((item) => item.id === serviceItemId)
    if (!currentItem) {
      return
    }

    if (
      event.currentTarget instanceof HTMLInputElement &&
      event.currentTarget.list?.id === technicalSheetServiceItemListId &&
      currentItem.itemId.trim() === '' &&
      currentItem.itemLabel.trim() !== ''
    ) {
      openNewServiceItemFormFromTechnicalSheet(serviceItemId, currentItem.itemLabel)
      return
    }

    if (!isTechnicalSheetServiceItemComplete(currentItem)) {
      return
    }

    const isLastRow = technicalSheetServiceItems[technicalSheetServiceItems.length - 1]?.id === serviceItemId
    if (isLastRow) {
      addTechnicalSheetServiceItem()
      return
    }

    setEditingTechnicalSheetServiceItemId(null)
  }

  function openTechnicalSheetServiceItemModalFromDraft(serviceItemId: number) {
    const currentItem = technicalSheetServiceItems.find((item) => item.id === serviceItemId) ?? null
    if (!currentItem || currentItem.itemId.trim() !== '' || currentItem.itemLabel.trim() === '') {
      return
    }

    openNewServiceItemFormFromTechnicalSheet(serviceItemId, currentItem.itemLabel)
  }

  function toggleTechnicalSheetIngredient(ingredientId: number) {
    setTechnicalSheetIngredients((current) =>
      current.map((ingredient) =>
        ingredient.id === ingredientId ? { ...ingredient, isActive: !ingredient.isActive } : ingredient,
      ),
    )
    setEditingTechnicalSheetIngredientId((current) => (current === ingredientId ? null : current))
  }

  function deleteTechnicalSheetIngredient(ingredientId: number) {
    setTechnicalSheetIngredients((current) =>
      current.length === 1 ? current : current.filter((ingredient) => ingredient.id !== ingredientId),
    )
    setEditingTechnicalSheetIngredientId((current) => (current === ingredientId ? null : current))
  }

  function beginTechnicalSheetIngredientEdit(ingredientId: number) {
    setEditingTechnicalSheetIngredientId(ingredientId)
  }

  function toggleTechnicalSheetGarnishIngredient(ingredientId: number) {
    setTechnicalSheetGarnishIngredients((current) =>
      current.map((ingredient) =>
        ingredient.id === ingredientId ? { ...ingredient, isActive: !ingredient.isActive } : ingredient,
      ),
    )
    setEditingTechnicalSheetGarnishIngredientId((current) => (current === ingredientId ? null : current))
  }

  function deleteTechnicalSheetGarnishIngredient(ingredientId: number) {
    setTechnicalSheetGarnishIngredients((current) =>
      current.length === 1 ? current : current.filter((ingredient) => ingredient.id !== ingredientId),
    )
    setEditingTechnicalSheetGarnishIngredientId((current) => (current === ingredientId ? null : current))
  }

  function beginTechnicalSheetGarnishIngredientEdit(ingredientId: number) {
    setEditingTechnicalSheetGarnishIngredientId(ingredientId)
  }

  function toggleTechnicalSheetServiceItem(serviceItemId: number) {
    setTechnicalSheetServiceItems((current) =>
      current.map((item) =>
        item.id === serviceItemId ? { ...item, isActive: !item.isActive } : item,
      ),
    )
    setEditingTechnicalSheetServiceItemId((current) => (current === serviceItemId ? null : current))
  }

  function deleteTechnicalSheetServiceItem(serviceItemId: number) {
    setTechnicalSheetServiceItems((current) =>
      current.length === 1 ? current : current.filter((item) => item.id !== serviceItemId),
    )
    setEditingTechnicalSheetServiceItemId((current) => (current === serviceItemId ? null : current))
  }

  function beginTechnicalSheetServiceItemEdit(serviceItemId: number) {
    setEditingTechnicalSheetServiceItemId(serviceItemId)
  }

  async function saveTechnicalSheet() {
    if (isSavingTechnicalSheet) {
      return
    }

    const previousTechnicalSheet =
      editingTechnicalSheetId ? technicalSheets.find((sheet) => sheet.id === editingTechnicalSheetId) ?? null : null
    const normalizedName = normalizeRegistrationText(technicalSheetForm.name.trim())
    const normalizedFamily = normalizeRegistrationText(technicalSheetForm.family.trim())
    const normalizedSubfamily = normalizeRegistrationText(technicalSheetForm.subfamily.trim())
    const normalizedCompanyProductId = normalizeRegistrationText(technicalSheetForm.companyProductId.trim())
    const normalizedSectors = technicalSheetForm.sectors
      .map((sector) => normalizeRegistrationText(sector.trim()))
      .filter(Boolean)
    const normalizedIngredients = technicalSheetIngredients
      .map((ingredient) => ({
        ...ingredient,
        productId: ingredient.productId,
        productLabel: ingredient.productLabel,
        quantity: ingredient.quantity.trim(),
        yieldQuantity: ingredient.yieldQuantity.trim(),
      }))
      .filter(
        (ingredient) =>
          ingredient.isActive &&
          ingredient.productId.trim() !== '' &&
          ingredient.quantity !== '' &&
          ingredient.yieldQuantity !== '',
      )
    const normalizedGarnishIngredients =
      technicalSheetForm.kind === 'EXECUCAO'
        ? technicalSheetGarnishIngredients
            .map((ingredient) => ({
              ...ingredient,
              productId: ingredient.productId,
              productLabel: ingredient.productLabel,
              quantity: ingredient.quantity.trim(),
              yieldQuantity: ingredient.yieldQuantity.trim(),
            }))
            .filter(
              (ingredient) =>
                ingredient.isActive &&
                ingredient.productId.trim() !== '' &&
                ingredient.quantity !== '' &&
                ingredient.yieldQuantity !== '',
            )
        : []
    const normalizedServiceItems =
      technicalSheetForm.kind === 'EXECUCAO' || technicalSheetForm.kind === 'PREPARO'
        ? technicalSheetServiceItems
            .map((item) => ({
              ...item,
              itemId: item.itemId,
              itemLabel: item.itemLabel,
              quantity: item.quantity.trim(),
            }))
            .filter((item) => item.isActive && item.itemId.trim() !== '' && item.quantity !== '')
        : []
    const normalizedProductionCenters =
      technicalSheetForm.kind === 'PREPARO'
        ? technicalSheetForm.productionCenters
            .filter((item) =>
              activeProducerStockCenters.some((center) => center.id === item.stockCenterId) ||
              stockCenters.some((center) => center.companyId === currentCompanyId && center.id === item.stockCenterId),
            )
            .map((item) => ({
              stockCenterId: item.stockCenterId,
              minimumQuantity: item.minimumQuantity.trim(),
            }))
        : []

    const errors: string[] = []

    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'companyProductId') && !normalizedCompanyProductId) {
      errors.push('id empresa obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'name') && !normalizedName) {
      errors.push('nome da ficha obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'family') && !normalizedFamily) {
      errors.push('familia obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'subfamily') && !normalizedSubfamily) {
      errors.push('subfamilia obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'sectors') && normalizedSectors.length === 0) {
      errors.push('ao menos 1 setor obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'ingredients') && normalizedIngredients.length === 0) {
      errors.push('adicione ao menos 1 produto na ficha')
    }
    if (
      isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'productionCenters') &&
      normalizedProductionCenters.length === 0
    ) {
      errors.push('defina ao menos 1 centro produtor')
    }
    if (technicalSheetTotals.totalYield <= 0) {
      errors.push('o rendimento final da ficha precisa ser maior que zero')
    }
    if (technicalSheetForm.kind === 'PREPARO' && technicalSheetTotals.yieldDifferenceQuantity > 0) {
      if (!technicalSheetForm.yieldDifferenceDestination) {
        errors.push('classifique a diferenca negativa de rendimento')
      }
      if (
        technicalSheetForm.yieldDifferenceDestination === 'BYPRODUCT' &&
        !normalizeRegistrationText(technicalSheetForm.yieldDifferenceByproductName.trim())
      ) {
        errors.push('informe o nome do subproduto')
      }
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'portionSize') && !technicalSheetForm.portionSize.trim()) {
      errors.push('porcao base obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'preparationMode') && !technicalSheetForm.preparationMode.trim()) {
      errors.push('modo de preparo obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'storytelling') && !technicalSheetForm.storytelling.trim()) {
      errors.push('storytelling obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'densitySampleVolume') && !technicalSheetForm.densitySampleVolume.trim()) {
      errors.push('volume da amostra obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'densitySampleWeight') && !technicalSheetForm.densitySampleWeight.trim()) {
      errors.push('peso da amostra obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'targetPh') && !technicalSheetForm.targetPh.trim()) {
      errors.push('meta de ph obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'targetBrix') && !technicalSheetForm.targetBrix.trim()) {
      errors.push('meta de brix obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'imageDataUrl') && !technicalSheetForm.imageDataUrl.trim()) {
      errors.push('imagem do produto obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'garnishIngredients') && normalizedGarnishIngredients.length === 0) {
      errors.push('adicione ao menos 1 guarnicao na ficha')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'serviceItems') && normalizedServiceItems.length === 0) {
      errors.push('adicione ao menos 1 recipiente na ficha')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'shelfLifeRoom') && !technicalSheetForm.shelfLifeRoom.trim()) {
      errors.push('validade in natura obrigatoria')
    }
    if (
      isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'shelfLifeRefrigerated') &&
      !technicalSheetForm.shelfLifeRefrigerated.trim()
    ) {
      errors.push('validade refrigerado obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'shelfLifeFrozen') && !technicalSheetForm.shelfLifeFrozen.trim()) {
      errors.push('validade congelado obrigatoria')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'flavorSweet') && !technicalSheetForm.flavorSweet.trim()) {
      errors.push('campo doce obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'flavorSour') && !technicalSheetForm.flavorSour.trim()) {
      errors.push('campo azedo obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'flavorBitter') && !technicalSheetForm.flavorBitter.trim()) {
      errors.push('campo amargo obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'flavorSalty') && !technicalSheetForm.flavorSalty.trim()) {
      errors.push('campo salgado obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'flavorUmami') && !technicalSheetForm.flavorUmami.trim()) {
      errors.push('campo umami obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'finalSalePrice') && !technicalSheetForm.finalSalePrice.trim()) {
      errors.push('valor de venda final obrigatorio')
    }
    if (isTechnicalSheetFieldRequired(technicalSheetForm.kind, 'desiredCmvPercentage')) {
      const desiredCmv = parseDecimal(technicalSheetForm.desiredCmvPercentage)
      if (!desiredCmv || desiredCmv <= 0) {
        errors.push('cmv desejado obrigatorio')
      }
    }

    if (errors.length > 0) {
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar ficha tecnica',
        message: `Erro: ${errors.join('; ')}.`,
      })
      return
    }

    const normalizedNameKey = buildNormalizedRegistrationNameKey(normalizedName)
    const duplicateTechnicalSheet = technicalSheets.find(
      (sheet) =>
        sheet.companyId === (currentCompanyId ?? 0) &&
        sheet.id !== editingTechnicalSheetId &&
        buildNormalizedRegistrationNameKey(sheet.name) === normalizedNameKey,
    )
    if (duplicateTechnicalSheet) {
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar ficha tecnica',
        message: `Ja existe uma ficha tecnica cadastrada com o nome ${normalizedName}.`,
      })
      return
    }

    const technicalSheetId =
      editingTechnicalSheetId ??
      (technicalSheets.length > 0 ? Math.max(...technicalSheets.map((item) => item.id)) + 1 : 1)
    const generatedProductId = previousTechnicalSheet?.productId ?? buildTechnicalSheetProductId(normalizedName, technicalSheetForm.kind)

    const technicalSheetToSave: TechnicalSheetRecord = {
      id: technicalSheetId,
      companyId: currentCompanyId ?? 0,
      kind: technicalSheetForm.kind,
      productId: generatedProductId,
      companyProductId: normalizedCompanyProductId,
      name: normalizedName,
      family: normalizedFamily,
      subfamily: normalizedSubfamily,
      sectors: normalizedSectors,
      outputQuantity: formatDecimal(technicalSheetTotals.totalYield),
      outputUnit: technicalSheetForm.outputUnit,
      densitySampleVolume: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : technicalSheetForm.densitySampleVolume.trim(),
      densitySampleWeight: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : technicalSheetForm.densitySampleWeight.trim(),
      yieldDifferenceDestination: technicalSheetForm.kind === 'PREPARO' ? technicalSheetForm.yieldDifferenceDestination : '',
      yieldDifferenceByproductName:
        technicalSheetForm.kind === 'PREPARO'
          ? normalizeRegistrationText(technicalSheetForm.yieldDifferenceByproductName.trim())
          : '',
      yieldDifferenceByproductTechnicalSheetId:
        technicalSheetForm.kind === 'PREPARO' ? technicalSheetForm.yieldDifferenceByproductTechnicalSheetId : null,
      targetPh: technicalSheetForm.kind === 'PREPARO' ? technicalSheetForm.targetPh.trim() : '',
      targetBrix: technicalSheetForm.kind === 'PREPARO' ? technicalSheetForm.targetBrix.trim() : '',
      portionSize: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '1' : technicalSheetForm.portionSize.trim(),
      colorTagOne: technicalSheetForm.kind === 'PREPARO' ? technicalSheetForm.colorTagOne.trim() : '',
      colorTagTwo: technicalSheetForm.kind === 'PREPARO' ? technicalSheetForm.colorTagTwo.trim() : '',
      desiredCmvPercentage: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? technicalSheetForm.desiredCmvPercentage.trim() : '',
      dilutionRatePercentage: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.dilutionRatePercentage.trim() : '',
      imageDataUrl: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.imageDataUrl : '',
      finalSalePrice:
        isCommercialTechnicalSheetKind(technicalSheetForm.kind)
          ? technicalSheetForm.finalSalePrice.trim()
          : '',
      flavorSweet: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.flavorSweet.trim() || '0' : '0',
      flavorSour: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.flavorSour.trim() || '0' : '0',
      flavorBitter: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.flavorBitter.trim() || '0' : '0',
      flavorSalty: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.flavorSalty.trim() || '0' : '0',
      flavorUmami: technicalSheetForm.kind === 'EXECUCAO' ? technicalSheetForm.flavorUmami.trim() || '0' : '0',
      storytelling: technicalSheetForm.kind === 'EXECUCAO' ? normalizeFreeText(technicalSheetForm.storytelling.trim()) : '',
      preparationMode: technicalSheetForm.kind === 'VENDA' ? '' : normalizeFreeText(technicalSheetForm.preparationMode.trim()),
      shelfLifeRoom: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : normalizeRegistrationText(technicalSheetForm.shelfLifeRoom.trim()),
      shelfLifeRefrigerated:
        isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : normalizeRegistrationText(technicalSheetForm.shelfLifeRefrigerated.trim()),
      shelfLifeFrozen: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : normalizeRegistrationText(technicalSheetForm.shelfLifeFrozen.trim()),
      productionCenters: normalizedProductionCenters,
      ingredients: normalizedIngredients,
      garnishIngredients: normalizedGarnishIngredients,
      serviceItems: normalizedServiceItems,
      isActive: true,
    }

    const baseSheets = editingTechnicalSheetId
      ? technicalSheets.map((item) => (item.id === editingTechnicalSheetId ? technicalSheetToSave : item))
      : [technicalSheetToSave, ...technicalSheets]

    const nextTechnicalSheets = previousTechnicalSheet
      ? syncTechnicalSheetIngredientReferences(
          baseSheets,
          previousTechnicalSheet.productId,
          technicalSheetToSave.productId,
          technicalSheetToSave.name,
        )
      : baseSheets

    const linkedExisting = products.find((product) => product.technicalSheetId === technicalSheetId)
    const technicalProduct: ProductRecord = {
      companyId: currentCompanyId ?? 0,
      id: generatedProductId,
      companyProductId: normalizedCompanyProductId,
      name: normalizedName,
      controlUnit: technicalSheetForm.outputUnit,
      family: normalizedFamily,
      subfamily: normalizedSubfamily,
      sectors: normalizedSectors,
      alcoholPercentage:
        technicalSheetForm.kind === 'PREPARO'
          ? formatDecimal(calculateTechnicalSheetAlcoholPercentage(technicalSheetToSave, nextTechnicalSheets, products))
          : '',
      densitySampleVolume: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : technicalSheetForm.densitySampleVolume.trim(),
      densitySampleWeight: isCommercialTechnicalSheetKind(technicalSheetForm.kind) ? '' : technicalSheetForm.densitySampleWeight.trim(),
      ignoreStock: linkedExisting?.ignoreStock ?? false,
      isActive: true,
      packages: linkedExisting?.packages ?? [],
      technicalSheetId: technicalSheetId,
    }

    const nextProducts = linkedExisting
      ? products.map((product) =>
          product.technicalSheetId === technicalSheetId ? { ...linkedExisting, ...technicalProduct } : product,
        )
      : [technicalProduct, ...products]

    setIsSavingTechnicalSheet(true)
    setSaveProgressState({
      title: 'Registrando ficha tecnica',
      message: 'Registrando, aguarde. Nao feche a tela nem clique novamente em salvar.',
    })
    try {
      await upsertTechnicalSheetRecordOnApi(technicalSheetToSave)
      await persistChangedTechnicalSheetsOnApi(technicalSheets, nextTechnicalSheets)
      await upsertProductRecordOnApi(technicalProduct, linkedExisting?.id ?? null)
      if (
        previousTechnicalSheet &&
        previousTechnicalSheet.productId !== technicalProduct.id &&
        linkedExisting?.id !== previousTechnicalSheet.productId
      ) {
        const deleteResponse = await fetch(`/api/products/${encodeURIComponent(previousTechnicalSheet.productId)}`, {
          method: 'DELETE',
        })
        if (!deleteResponse.ok) {
          throw new Error('A ficha tecnica foi salva, mas nao foi possivel limpar o produto vinculado anterior.')
        }
      }
    } catch (error) {
      console.error(error)
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao salvar ficha tecnica',
        message: error instanceof Error ? error.message : 'Erro ao salvar ficha tecnica no servidor.',
      })
      return
    } finally {
      setIsSavingTechnicalSheet(false)
      setSaveProgressState(null)
    }

    setTechnicalSheets(nextTechnicalSheets)
    setProducts(nextProducts)
    await refreshAppCatalogRecordsFromApi()
    setStockCenters((current) =>
      current.map((center) => {
        const remainingProducedIds = center.producedTechnicalSheetIds.filter((sheetId) => sheetId !== technicalSheetId)
        const remainingMinimumStocks = center.minimumStocks.filter(
          (item) => !(item.kind === 'PREPARO' && item.technicalSheetId === technicalSheetId),
        )
        const productionAssignment =
          technicalSheetToSave.kind === 'PREPARO'
            ? technicalSheetToSave.productionCenters.find((item) => item.stockCenterId === center.id) ?? null
            : null

        if (!productionAssignment) {
          return {
            ...center,
            producedTechnicalSheetIds: remainingProducedIds,
            minimumStocks: remainingMinimumStocks,
          }
        }

        return {
          ...center,
          isProducer: true,
          producedTechnicalSheetIds: Array.from(new Set([...remainingProducedIds, technicalSheetId])),
          minimumStocks: productionAssignment.minimumQuantity
            ? [
                ...remainingMinimumStocks,
                {
                  kind: 'PREPARO',
                  technicalSheetId,
                  productId: '',
                  serviceItemId: '',
                  packageId: null,
                  minimumQuantity: productionAssignment.minimumQuantity,
                },
              ]
            : remainingMinimumStocks,
        }
      }),
    )

    if (pendingNestedTechnicalSheetKind === technicalSheetForm.kind) {
      if (pendingNestedTechnicalSheetPurpose === 'subproduct') {
        restoreTopTechnicalSheetDraft()
        setTechnicalSheetForm((current) => ({
          ...current,
          yieldDifferenceDestination: 'BYPRODUCT',
          yieldDifferenceByproductName: normalizedName,
          yieldDifferenceByproductTechnicalSheetId: technicalSheetId,
        }))
      } else {
        restoreTechnicalSheetDraftWithCreatedIngredient(generatedProductId, normalizedName)
      }
      setSaveFeedback({
        status: 'success',
        title: 'Ficha tecnica salva com sucesso',
        message:
          pendingNestedTechnicalSheetPurpose === 'subproduct'
            ? 'A ficha tecnica do subproduto foi cadastrada e vinculada ao pre-preparo anterior.'
            : 'A ficha tecnica foi cadastrada e vinculada ao insumo em edicao na ficha anterior.',
      })
      return
    }

    setTechnicalSheetScreenMode('list')
    setEditingTechnicalSheetId(null)
    setTechnicalSheetForm(emptyTechnicalSheetForm())
    setTechnicalSheetSectorInput('')
    setTechnicalSheetIngredients([emptyTechnicalSheetIngredient()])
    setTechnicalSheetGarnishIngredients([emptyTechnicalSheetIngredient()])
    setEditingTechnicalSheetGarnishIngredientId(null)
    setTechnicalSheetServiceItems([emptyTechnicalSheetServiceItem()])
    setEditingTechnicalSheetServiceItemId(null)
    setTechnicalSheetPackages([])
    setSaveFeedback({
      status: 'success',
      title: editingTechnicalSheetId ? 'Ficha tecnica atualizada com sucesso' : 'Ficha tecnica salva com sucesso',
      message:
        editingTechnicalSheetId
          ? 'A ficha tecnica foi atualizada e o produto vinculado tambem foi atualizado.'
          : 'A ficha tecnica foi cadastrada e o produto vinculado ja entrou na lista de produtos.',
    })
  }

  function closeSaveFeedback() {
    const wasSuccess = saveFeedback?.status === 'success'
    setSaveFeedback(null)
    if (wasSuccess) {
      setScreenMode('list')
      setItemScreenMode('list')
    }
  }

  function openStockReportExportModal() {
    setStockReportExportState({
      format: 'pdf',
    })
  }

  function buildProductExportFileName(extension: 'pdf' | 'xlsx') {
    const companyLabel = currentCompany?.tradeName || 'EMPRESA'
    const normalizedCompanyLabel = companyLabel
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^A-Z0-9]+/gi, '-')
      .replace(/^-+|-+$/g, '')
      .toUpperCase()

    return `PRODUTOS-${normalizedCompanyLabel || 'EMPRESA'}.${extension}`
  }

  function buildStockReportExportFileName(extension: 'pdf' | 'xlsx') {
    const companyLabel = currentCompany?.tradeName || 'EMPRESA'
    const normalizedCompanyLabel = companyLabel
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^A-Z0-9]+/gi, '-')
      .replace(/^-+|-+$/g, '')
      .toUpperCase()
    const reportLabel =
      stockReportTabDefinitions.find((definition) => definition.key === stockReportTab)?.label ?? 'RELATORIO'
    const normalizedReportLabel = reportLabel
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^A-Z0-9]+/gi, '-')
      .replace(/^-+|-+$/g, '')
      .toUpperCase()

    return `RELATORIO-${normalizedReportLabel || 'RELATORIO'}-${normalizedCompanyLabel || 'EMPRESA'}.${extension}`
  }

  function confirmProductExport() {
    if (!productExportState) {
      return
    }

    if (visibleProducts.length === 0) {
      setProductExportState(null)
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao exportar produtos',
        message: 'Erro: nao existem produtos visiveis na lista para exportacao com os filtros atuais.',
      })
      return
    }

    const headers = [
      'Tipo',
      'Produto',
      'ID interno',
      'ID empresa',
      'Familia',
      'Subfamilia',
      'Setores',
      'Unidade',
      'Custo por unidade',
      'Embalagens',
      'Status',
      'Sub-ID embalagem',
      'Embalagem',
      'Codigo de barras',
      'Peso bruto (g)',
      'Peso embalagem (g)',
      'Valor compra',
      'Status embalagem',
    ]

    const rows = exportableProductRows.map((item) => [
      item.tipo,
      item.produto,
      item.idInterno,
      item.idEmpresa,
      item.familia,
      item.subfamilia,
      item.setores,
      item.unidade,
      item.custoUnitario,
      item.embalagens,
      item.status,
      item.subIdEmbalagem,
      item.embalagem,
      item.codigoBarras,
      item.pesoBruto,
      item.pesoEmbalagem,
      item.valorCompra,
      item.statusEmbalagem,
    ])

    if (productExportState.format === 'xlsx') {
      const worksheet = XLSX.utils.aoa_to_sheet([headers, ...rows])
      const workbook = XLSX.utils.book_new()
      XLSX.utils.book_append_sheet(workbook, worksheet, 'Produtos')
      XLSX.writeFile(workbook, buildProductExportFileName('xlsx'))
    } else {
      const doc = new jsPDF({
        orientation: 'landscape',
        unit: 'pt',
        format: 'a4',
      })

      doc.setFontSize(14)
      doc.text('Produtos cadastrados', 40, 32)
      doc.setFontSize(9)
      doc.text(
        `Empresa: ${currentCompany?.tradeName || '-'} | Registros: ${visibleProducts.length} | Embalagens: ${
          productExportState.includePackages ? 'SIM' : 'NAO'
        }`,
        40,
        48,
      )

      autoTable(doc, {
        head: [headers],
        body: rows,
        startY: 60,
        styles: {
          fontSize: 7,
          cellPadding: 4,
          overflow: 'linebreak',
        },
        headStyles: {
          fillColor: [15, 72, 124],
        },
        columnStyles: {
          0: { cellWidth: 50 },
          1: { cellWidth: 110 },
          2: { cellWidth: 80 },
          8: { cellWidth: 60, halign: 'right' },
          11: { cellWidth: 70 },
          12: { cellWidth: 70 },
        },
      })

      doc.save(buildProductExportFileName('pdf'))
    }

    setProductExportState(null)
    setSaveFeedback({
      status: 'success',
      title: 'Exportacao concluida',
      message: `A lista de produtos foi exportada em ${productExportState.format.toUpperCase()} considerando os filtros atuais.`,
    })
  }

  function confirmStockReportExport() {
    if (!stockReportExportState) {
      return
    }

    if (stockReportNeedsCenterSelection) {
      setStockReportExportState(null)
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao exportar relatorio',
        message: 'Selecione pelo menos um centro de estoque para exportar este relatorio.',
      })
      return
    }

    if (visibleStockReportRows.length === 0 || orderedVisibleStockReportColumns.length === 0) {
      setStockReportExportState(null)
      setSaveFeedback({
        status: 'error',
        title: 'Falha ao exportar relatorio',
        message: 'Nao existem linhas visiveis no relatorio para exportar com os filtros atuais.',
      })
      return
    }

    const reportLabel = stockReportTabDefinitions.find((definition) => definition.key === stockReportTab)?.label ?? 'Relatorio'
    const headers = orderedVisibleStockReportColumns.map((key) => getStockReportColumnLabel(key, stockReportTab))
    const rows = visibleStockReportRows.map((row) =>
      orderedVisibleStockReportColumns.map((key) => {
        const value = getStockReportColumnValue(row, key)
        return value && value.trim() !== '' ? value : '-'
      }),
    )

    const scopeLabel = stockReportUsesCenterScope
      ? stockPositionReportScope === 'GLOBAL'
        ? 'ESTOQUE GLOBAL'
        : stockReportSelectedCenters.length > 0
          ? stockReportSelectedCenters.join(', ')
          : 'CENTROS DE ESTOQUE'
      : 'NAO SE APLICA'
    const periodLabel = stockReportUsesDateRange
      ? `${stockReportStartDate || '-'} ate ${stockReportEndDate || '-'}`
      : 'NAO SE APLICA'
    const searchLabel = stockReportSearch.trim() || '-'
    const sortLabel = stockReportColumnSort
      ? `${getStockReportColumnLabel(stockReportColumnSort.key, stockReportTab)} (${stockReportColumnSort.direction === 'asc' ? 'ASC' : 'DESC'})`
      : '-'

    if (stockReportExportState.format === 'xlsx') {
      const worksheet = XLSX.utils.aoa_to_sheet([
        ['Empresa', currentCompany?.tradeName || '-'],
        ['Relatorio', reportLabel],
        ['Visualizacao', scopeLabel],
        ['Periodo', periodLabel],
        ['Busca', searchLabel],
        ['Ordenacao', sortLabel],
        ['Registros visiveis', String(visibleStockReportRows.length)],
        [],
        headers,
        ...rows,
      ])
      const workbook = XLSX.utils.book_new()
      const sheetName = reportLabel
        .replace(/[\\/?*\[\]:]/g, ' ')
        .trim()
        .slice(0, 31) || 'Relatorio'
      XLSX.utils.book_append_sheet(workbook, worksheet, sheetName)
      XLSX.writeFile(workbook, buildStockReportExportFileName('xlsx'))
    } else {
      const doc = new jsPDF({
        orientation: headers.length > 6 ? 'landscape' : 'portrait',
        unit: 'pt',
        format: 'a4',
      })

      doc.setFontSize(14)
      doc.text(reportLabel, 40, 32)
      doc.setFontSize(9)
      doc.text(`Empresa: ${currentCompany?.tradeName || '-'} | Registros: ${visibleStockReportRows.length}`, 40, 48)
      doc.text(`Visualizacao: ${scopeLabel}`, 40, 62)
      doc.text(`Periodo: ${periodLabel}`, 40, 76)
      doc.text(`Busca: ${searchLabel}`, 40, 90)
      doc.text(`Ordenacao: ${sortLabel}`, 40, 104)

      autoTable(doc, {
        head: [headers],
        body: rows,
        startY: 116,
        styles: {
          fontSize: 7,
          cellPadding: 4,
          overflow: 'linebreak',
        },
        headStyles: {
          fillColor: [15, 72, 124],
        },
      })

      doc.save(buildStockReportExportFileName('pdf'))
    }

    setStockReportExportState(null)
    setSaveFeedback({
      status: 'success',
      title: 'Exportacao concluida',
      message: `O relatorio exibido foi exportado em ${stockReportExportState.format.toUpperCase()} com os filtros e colunas visiveis atuais.`,
    })
  }

  function openRecipeExportModal() {
    setRecipeExportState({
      format: 'pdf',
      scope: 'current',
    })
  }

  function buildRecipeExportFileName(
    tab: RecipePanelTab,
    scope: RecipeExportState['scope'],
    extension: 'pdf' | 'xlsx',
  ) {
    const companyLabel = currentCompany?.tradeName || 'EMPRESA'
    const normalizedCompanyLabel = companyLabel
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^A-Z0-9]+/gi, '-')
      .replace(/^-+|-+$/g, '')
      .toUpperCase()
    const tabLabel = tab === 'PREPARO' ? 'PRE-PREPAROS' : 'EXECUCAO'
    const scopeLabel = scope === 'current' ? 'FICHA-ATUAL' : 'TODAS-AS-FICHAS'

    return `RECEITUARIOS-${tabLabel}-${scopeLabel}-${normalizedCompanyLabel || 'EMPRESA'}.${extension}`
  }

  function buildRecipeExportSheetName(value: string) {
    const normalized = value
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[\\/?*:[\]]+/g, ' ')
      .trim()

    return (normalized || 'Ficha').slice(0, 31)
  }

  function buildRecipePreparationText(data: RecipePanelComputedData) {
    return buildPreparationModeMetricParts(data.sheet.preparationMode, data.ingredientMetrics)
      .map((part) => (part.type === 'ingredient' ? `${part.quantityLabel} ${part.text}` : part.text))
      .join('')
      .replace(/\s+\n/g, '\n')
      .trim()
  }

