                            {requisitionHistoryColumnVisibility.createdBy ? renderRequisitionHistoryColumnHeader('createdBy', 'Criada por', openRequisitionHistoryColumnMenu, setOpenRequisitionHistoryColumnMenu, requisitionHistoryColumnFilters, distinctRequisitionHistoryColumnValues, setRequisitionHistoryColumnFilters, setRequisitionHistoryColumnVisibility, requisitionHistoryColumnSort, setRequisitionHistoryColumnSort) : null}
