                            {requisitionHistoryColumnVisibility.destinations ? renderRequisitionHistoryColumnHeader('destinations', 'Destinos', openRequisitionHistoryColumnMenu, setOpenRequisitionHistoryColumnMenu, requisitionHistoryColumnFilters, distinctRequisitionHistoryColumnValues, setRequisitionHistoryColumnFilters, setRequisitionHistoryColumnVisibility, requisitionHistoryColumnSort, setRequisitionHistoryColumnSort) : null}
