                            {receiveColumnVisibility.supply ? renderRequisitionFlowColumnHeader('supply', 'Suprimentos', openReceiveColumnMenu, setOpenReceiveColumnMenu, receiveColumnFilters, distinctReceiveColumnValues, setReceiveColumnFilters, setReceiveColumnVisibility, receiveColumnSort, setReceiveColumnSort) : null}
