function loadAuthState(): {
  session: Session
  currentCompanyId: number | null
} {
  if (typeof window === 'undefined') {
    return { session: null, currentCompanyId: null }
  }

  try {
    const raw = window.localStorage.getItem(authStorageKey)
    if (!raw) {
      return { session: null, currentCompanyId: null }
    }

    const parsed = JSON.parse(raw) as Partial<{
      session: Session
      companies: CompanyRecord[]
      currentCompanyId: number | null
    }>

    let session: Session = null
    if (parsed.session?.kind === 'systemAdmin') {
      session = parsed.session
    } else if (parsed.session?.kind === 'appUser') {
      session = normalizeSessionUser(parsed.session.user)
        ? { kind: 'appUser', user: normalizeSessionUser(parsed.session.user) as AppUserRecord }
        : null
    }

    return {
      session,
      currentCompanyId:
        typeof parsed.currentCompanyId === 'number' ? parsed.currentCompanyId : null,
    }
  } catch {
    return { session: null, currentCompanyId: null }
  }
}

function saveAuthState(state: {
  session: Session
  currentCompanyId: number | null
}) {
  if (typeof window === 'undefined') {
    return
  }

  try {
    window.localStorage.setItem(authStorageKey, JSON.stringify(state))
  } catch {
    return
  }
}

function loadCompaniesState(): CompanyRecord[] {
  if (typeof window === 'undefined') {
    return []
  }

  try {
    const raw = window.localStorage.getItem(companiesStorageKey)
    if (raw) {
      const parsed = JSON.parse(raw) as unknown
      if (Array.isArray(parsed)) {
        return parsed
          .map(normalizeCompanyRecord)
          .filter((company): company is CompanyRecord => company !== null)
      }
    }

    // Fallback for older builds that persisted companies inside auth state.
    const legacyRaw = window.localStorage.getItem(authStorageKey)
    if (!legacyRaw) {
      return []
    }

    const legacyParsed = JSON.parse(legacyRaw) as Partial<{ companies: CompanyRecord[] }>
    return Array.isArray(legacyParsed.companies)
      ? legacyParsed.companies
          .map(normalizeCompanyRecord)
          .filter((company): company is CompanyRecord => company !== null)
      : []
  } catch {
    return []
  }
}

