function loadTechnicalSheetsState(): TechnicalSheetRecord[] {
  if (typeof window === 'undefined') {
    return []
  }

  try {
    const raw = window.localStorage.getItem(technicalSheetsStorageKey)
    if (!raw) {
      return recoverTechnicalSheetsFromProductsStorage()
    }

    const parsed = JSON.parse(raw) as unknown
    if (!Array.isArray(parsed)) {
      return recoverTechnicalSheetsFromProductsStorage()
    }

    const technicalSheets = parsed
      .map(normalizeTechnicalSheetRecord)
      .filter((item): item is TechnicalSheetRecord => item !== null)

    return technicalSheets.length > 0 ? technicalSheets : recoverTechnicalSheetsFromProductsStorage()
  } catch {
    return recoverTechnicalSheetsFromProductsStorage()
  }
}

