function normalizePendingInventoryMovementRecord(value: unknown): PendingInventoryMovementRecord | null {
  if (!value || typeof value !== 'object') {
    return null
  }

  const record = value as Partial<PendingInventoryMovementRecord>
  if (
    typeof record.id !== 'number' ||
    typeof record.companyId !== 'number' ||
    typeof record.stockCenterId !== 'number' ||
    typeof record.inventoryId !== 'number' ||
    typeof record.createdAt !== 'string' ||
    typeof record.description !== 'string'
  ) {
    return null
  }

  const session = normalizeInventoryCountSessionRecord(record.session)
  const records = Array.isArray(record.records)
    ? record.records
        .map(normalizeInventoryCountRecord)
        .filter((item): item is InventoryCountRecord => item !== null)
    : []

  if (!session || records.length === 0) {
    return null
  }

  return {
    id: record.id,
    companyId: record.companyId,
    stockCenterId: record.stockCenterId,
    inventoryId: record.inventoryId,
    createdAt: record.createdAt,
    createdByUserId: typeof record.createdByUserId === 'number' ? record.createdByUserId : null,
    createdByUserName:
      typeof record.createdByUserName === 'string' && record.createdByUserName.trim()
        ? record.createdByUserName
        : 'Administrador do sistema',
    description: record.description,
    session,
    records,
  }
}

