function normalizeTechnicalSheetSettingsRecord(value: unknown): TechnicalSheetSettingsRecord | null {
  if (!value || typeof value !== 'object') {
    return null
  }

  const record = value as Partial<TechnicalSheetSettingsRecord>
  if (typeof record.companyId !== 'number' || !record.settings || typeof record.settings !== 'object') {
    return null
  }

  const defaultSettings = buildDefaultTechnicalSheetFormSettings()
  const nextSettings = { ...defaultSettings }

  ;(['PREPARO', 'EXECUCAO', 'VENDA'] as const).forEach((kind) => {
    const rawKindSettings = record.settings?.[kind]
    if (!rawKindSettings || typeof rawKindSettings !== 'object') {
      return
    }

    technicalSheetConfigurationFieldDefinitions.forEach((definition) => {
      const rawFieldSettings = rawKindSettings[definition.key]
      if (!rawFieldSettings || typeof rawFieldSettings !== 'object') {
        return
      }

      nextSettings[kind][definition.key] = {
        visible:
          isTechnicalSheetConfigurationFieldApplicable(kind, definition.key) &&
          rawFieldSettings.visible !== false,
        required:
          isTechnicalSheetConfigurationFieldApplicable(kind, definition.key) &&
          rawFieldSettings.visible !== false &&
          rawFieldSettings.required === true,
      }
    })
  })

  return {
    companyId: record.companyId,
    settings: nextSettings,
  }
}

function normalizeProductRecord(value: unknown): ProductRecord | null {
  if (!value || typeof value !== 'object') {
    return null
  }

  const product = value as Partial<ProductRecord>
  const normalizedProductControlUnit = normalizeControlUnit(product.controlUnit)
  if (
    typeof product.id !== 'string' ||
    typeof product.companyProductId !== 'string' ||
    typeof product.name !== 'string' ||
    normalizedProductControlUnit === null ||
    typeof product.family !== 'string' ||
    typeof product.subfamily !== 'string' ||
    !Array.isArray(product.sectors) ||
    typeof product.alcoholPercentage !== 'string' ||
    typeof product.densitySampleVolume !== 'string' ||
    typeof product.densitySampleWeight !== 'string' ||
    typeof product.isActive !== 'boolean' ||
    !Array.isArray(product.packages)
  ) {
    return null
  }

  const packages = product.packages
    .map(normalizePackageForm)
    .filter((item): item is PackageForm => item !== null)

  return {
    companyId: typeof product.companyId === 'number' ? product.companyId : 1,
    id: normalizeRegistrationText(product.id),
    companyProductId: normalizeRegistrationText(product.companyProductId),
    name: normalizeRegistrationText(product.name),
    controlUnit: normalizedProductControlUnit,
    family: normalizeRegistrationText(product.family),
    subfamily: normalizeRegistrationText(product.subfamily),
    sectors: product.sectors
      .filter((sector): sector is string => typeof sector === 'string')
      .map((sector) => normalizeRegistrationText(sector))
      .filter(Boolean),
    alcoholPercentage: product.alcoholPercentage.trim(),
    densitySampleVolume: product.densitySampleVolume,
    densitySampleWeight: product.densitySampleWeight,
    ignoreStock: product.ignoreStock === true,
    isActive: product.isActive,
    packages,
    technicalSheetId: typeof product.technicalSheetId === 'number' ? product.technicalSheetId : undefined,
  }
}

