function normalizeTechnicalSheetRecord(value: unknown): TechnicalSheetRecord | null {
  if (!value || typeof value !== 'object') {
    return null
  }

  const item = value as Partial<TechnicalSheetRecord>
  const normalizedTechnicalSheetOutputUnit = normalizeControlUnit(item.outputUnit)
  if (
    typeof item.id !== 'number' ||
    typeof item.companyId !== 'number' ||
    typeof item.productId !== 'string' ||
    (item.kind !== undefined && item.kind !== 'PREPARO' && item.kind !== 'EXECUCAO' && item.kind !== 'VENDA') ||
    typeof item.companyProductId !== 'string' ||
    typeof item.name !== 'string' ||
    typeof item.family !== 'string' ||
    typeof item.subfamily !== 'string' ||
    !Array.isArray(item.sectors) ||
    typeof item.outputQuantity !== 'string' ||
    normalizedTechnicalSheetOutputUnit === null ||
    (item.yieldDifferenceDestination !== undefined &&
      item.yieldDifferenceDestination !== '' &&
      item.yieldDifferenceDestination !== 'WASTE' &&
      item.yieldDifferenceDestination !== 'BYPRODUCT') ||
    typeof item.preparationMode !== 'string' ||
    typeof item.shelfLifeRoom !== 'string' ||
    typeof item.shelfLifeRefrigerated !== 'string' ||
    typeof item.shelfLifeFrozen !== 'string' ||
    !Array.isArray(item.ingredients) ||
    typeof item.isActive !== 'boolean'
  ) {
    return null
  }

  return {
    id: item.id,
    companyId: item.companyId,
    kind: item.kind === 'VENDA' || item.kind === 'EXECUCAO' ? item.kind : 'PREPARO',
    productId: normalizeRegistrationText(item.productId),
    companyProductId: normalizeRegistrationText(item.companyProductId),
    name: normalizeRegistrationText(item.name),
    family: normalizeRegistrationText(item.family),
    subfamily: normalizeRegistrationText(item.subfamily),
    sectors: item.sectors
      .filter((sector): sector is string => typeof sector === 'string')
      .map((sector) => normalizeRegistrationText(sector))
      .filter(Boolean),
    outputQuantity: item.outputQuantity,
    outputUnit: normalizedTechnicalSheetOutputUnit,
    densitySampleVolume: typeof item.densitySampleVolume === 'string' ? item.densitySampleVolume : '',
    densitySampleWeight: typeof item.densitySampleWeight === 'string' ? item.densitySampleWeight : '',
    yieldDifferenceDestination:
      item.yieldDifferenceDestination === 'WASTE' || item.yieldDifferenceDestination === 'BYPRODUCT'
        ? item.yieldDifferenceDestination
        : '',
    yieldDifferenceByproductName: typeof item.yieldDifferenceByproductName === 'string' ? item.yieldDifferenceByproductName : '',
    yieldDifferenceByproductTechnicalSheetId:
      typeof item.yieldDifferenceByproductTechnicalSheetId === 'number' ? item.yieldDifferenceByproductTechnicalSheetId : null,
    targetPh: typeof item.targetPh === 'string' ? item.targetPh : '',
    targetBrix: typeof item.targetBrix === 'string' ? item.targetBrix : '',
    portionSize: typeof item.portionSize === 'string' ? item.portionSize : '1000',
    colorTagOne: typeof item.colorTagOne === 'string' ? item.colorTagOne : '',
    colorTagTwo: typeof item.colorTagTwo === 'string' ? item.colorTagTwo : '',
    desiredCmvPercentage: typeof item.desiredCmvPercentage === 'string' ? item.desiredCmvPercentage : '',
    dilutionRatePercentage: typeof item.dilutionRatePercentage === 'string' ? item.dilutionRatePercentage : '',
    imageDataUrl: typeof item.imageDataUrl === 'string' ? item.imageDataUrl : '',
    finalSalePrice: typeof item.finalSalePrice === 'string' ? item.finalSalePrice : '',
    flavorSweet: typeof item.flavorSweet === 'string' ? item.flavorSweet : '0',
    flavorSour: typeof item.flavorSour === 'string' ? item.flavorSour : '0',
    flavorBitter: typeof item.flavorBitter === 'string' ? item.flavorBitter : '0',
    flavorSalty: typeof item.flavorSalty === 'string' ? item.flavorSalty : '0',
    flavorUmami: typeof item.flavorUmami === 'string' ? item.flavorUmami : '0',
    storytelling: normalizeFreeText(typeof item.storytelling === 'string' ? item.storytelling : ''),
    preparationMode: normalizeFreeText(item.preparationMode),
    shelfLifeRoom: normalizeRegistrationText(item.shelfLifeRoom),
    shelfLifeRefrigerated: normalizeRegistrationText(item.shelfLifeRefrigerated),
    shelfLifeFrozen: normalizeRegistrationText(item.shelfLifeFrozen),
    productionCenters: Array.isArray(item.productionCenters)
      ? item.productionCenters
          .filter(
            (assignment): assignment is TechnicalSheetProductionCenter =>
              Boolean(assignment) &&
              typeof assignment === 'object' &&
              typeof assignment.stockCenterId === 'number' &&
              typeof assignment.minimumQuantity === 'string',
          )
          .map((assignment) => ({
            stockCenterId: assignment.stockCenterId,
            minimumQuantity: assignment.minimumQuantity.trim(),
          }))
      : [],
    ingredients: item.ingredients
      .filter((ingredient): ingredient is TechnicalSheetIngredient => {
        return (
          Boolean(ingredient) &&
          typeof ingredient === 'object' &&
          typeof ingredient.id === 'number' &&
          typeof ingredient.productId === 'string' &&
          typeof ingredient.productLabel === 'string' &&
          typeof ingredient.quantity === 'string' &&
          typeof ingredient.yieldQuantity === 'string'
        )
      })
      .map((ingredient) => ({
        id: ingredient.id,
        productId: ingredient.productId,
        productLabel: ingredient.productLabel,
        quantity: ingredient.quantity,
        yieldQuantity: ingredient.yieldQuantity,
        isActive: ingredient.isActive ?? true,
      })),
    garnishIngredients: Array.isArray(item.garnishIngredients)
      ? item.garnishIngredients
          .filter((ingredient): ingredient is TechnicalSheetIngredient => {
            return (
              Boolean(ingredient) &&
              typeof ingredient === 'object' &&
              typeof ingredient.id === 'number' &&
              typeof ingredient.productId === 'string' &&
              typeof ingredient.productLabel === 'string' &&
              typeof ingredient.quantity === 'string' &&
              typeof ingredient.yieldQuantity === 'string'
            )
          })
          .map((ingredient) => ({
            id: ingredient.id,
            productId: ingredient.productId,
            productLabel: ingredient.productLabel,
            quantity: ingredient.quantity,
            yieldQuantity: ingredient.yieldQuantity,
            isActive: ingredient.isActive ?? true,
          }))
      : [],
    serviceItems: Array.isArray(item.serviceItems)
      ? item.serviceItems
          .filter((serviceItem): serviceItem is TechnicalSheetServiceItem => {
            return (
              Boolean(serviceItem) &&
              typeof serviceItem === 'object' &&
              typeof serviceItem.id === 'number' &&
              typeof serviceItem.itemId === 'string' &&
              typeof serviceItem.itemLabel === 'string' &&
              typeof serviceItem.quantity === 'string'
            )
          })
          .map((serviceItem) => ({
            id: serviceItem.id,
            itemId: serviceItem.itemId,
            itemLabel: serviceItem.itemLabel,
            quantity: serviceItem.quantity,
            isActive: serviceItem.isActive ?? true,
          }))
      : [],
    isActive: item.isActive,
  }
}

function isLegacyImportedProduct(product: ProductRecord | null) {
  return product?.id.startsWith('IMP-') ?? false
}

function isCommercialTechnicalSheetKind(kind: TechnicalSheetKind) {
  return kind === 'VENDA' || kind === 'EXECUCAO'
}

function isExecutionTechnicalSheetKind(kind: TechnicalSheetKind) {
  return kind === 'EXECUCAO'
}

function getDefaultTechnicalSheetOutputUnit(kind: TechnicalSheetKind): ControlUnit {
  if (kind === 'EXECUCAO') {
    return 'UNIT'
  }

  if (kind === 'VENDA') {
    return 'UNIT'
  }

  return 'GRAM'
}

function isCommercialTechnicalSheetProduct(product: ProductRecord, technicalSheets: TechnicalSheetRecord[]) {
  if (typeof product.technicalSheetId !== 'number') {
    return false
  }

  const linkedTechnicalSheet = technicalSheets.find((sheet) => sheet.id === product.technicalSheetId) ?? null
  return linkedTechnicalSheet ? isCommercialTechnicalSheetKind(linkedTechnicalSheet.kind) : false
}

function getProductDisplayUnitLabel(product: ProductRecord, technicalSheets: TechnicalSheetRecord[]) {
  if (isCommercialTechnicalSheetProduct(product, technicalSheets)) {
    return 'UN'
  }

  return formatControlUnitShort(product.controlUnit)
}

function syncTechnicalSheetIngredientReferences(
  sheets: TechnicalSheetRecord[],
  previousProductId: string,
  nextProductId: string,
  nextProductLabel: string,
) {
  return sheets.map((sheet) => ({
    ...sheet,
    ingredients: sheet.ingredients.map((ingredient) =>
      ingredient.productId === previousProductId
        ? { ...ingredient, productId: nextProductId, productLabel: nextProductLabel }
        : ingredient,
    ),
    garnishIngredients: sheet.garnishIngredients.map((ingredient) =>
      ingredient.productId === previousProductId
        ? { ...ingredient, productId: nextProductId, productLabel: nextProductLabel }
        : ingredient,
    ),
  }))
}

function normalizePackageForm(value: unknown): PackageForm | null {
  if (!value || typeof value !== 'object') {
    return null
  }

  const item = value as Partial<PackageForm>
  if (
    typeof item.id !== 'number' ||
    typeof item.internalCode !== 'string' ||
    typeof item.barcode !== 'string' ||
    typeof item.packageQuantity !== 'string' ||
    (item.packageUnit !== 'LITER' &&
      item.packageUnit !== 'MILLILITER' &&
      item.packageUnit !== 'KILOGRAM' &&
      item.packageUnit !== 'GRAM' &&
      item.packageUnit !== 'UNIT') ||
    typeof item.grossWeightGrams !== 'string' ||
    typeof item.packagingWeightGrams !== 'string' ||
    typeof item.purchasePrice !== 'string' ||
    typeof item.openingQuantity !== 'string' ||
    typeof item.isActive !== 'boolean'
  ) {
    return null
  }

  return {
    id: item.id,
    internalCode: normalizeRegistrationText(item.internalCode),
    barcode: item.barcode,
    packageQuantity: item.packageQuantity,
    packageUnit: item.packageUnit,
    grossWeightGrams: item.grossWeightGrams,
    packagingWeightGrams: item.packagingWeightGrams,
    purchasePrice: item.purchasePrice,
    openingQuantity: item.openingQuantity,
    isActive: item.isActive,
  }
}

function normalizeControlUnit(value: unknown): ControlUnit | null {
  if (value === 'MILLILITER' || value === 'GRAM' || value === 'UNIT' || value === 'COMBO') {
    return value
  }

  return null
}

function normalizeRegistrationText(value: string) {
  const normalized = value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^A-Za-z0-9 ./_-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trimStart()

  return normalized.toUpperCase()
}

function hasSectorOverlap(itemSectors: string[], selectedSectors: string[]) {
  if (selectedSectors.length === 0) {
    return true
  }

  return itemSectors.some((sector) => selectedSectors.includes(sector))
}


function formatCep(value: string) {
  const digits = value.replace(/\D/g, '').slice(0, 8)
  if (digits.length <= 5) {
    return digits
  }

  return `${digits.slice(0, 5)}-${digits.slice(5)}`
}

function formatCnpj(value: string) {
  const digits = value.replace(/\D/g, '').slice(0, 14)

  if (digits.length <= 2) {
    return digits
  }
  if (digits.length <= 5) {
    return `${digits.slice(0, 2)}.${digits.slice(2)}`
  }
  if (digits.length <= 8) {
    return `${digits.slice(0, 2)}.${digits.slice(2, 5)}.${digits.slice(5)}`
  }
  if (digits.length <= 12) {
    return `${digits.slice(0, 2)}.${digits.slice(2, 5)}.${digits.slice(5, 8)}/${digits.slice(8)}`
  }

  return `${digits.slice(0, 2)}.${digits.slice(2, 5)}.${digits.slice(5, 8)}/${digits.slice(8, 12)}-${digits.slice(12)}`
}

function buildOpaqueCatalogId(prefix: string) {
  const timePart = Date.now().toString(36).toUpperCase()
  const randomPart = Math.random().toString(36).slice(2, 8).toUpperCase()
  return `${prefix}-${timePart}-${randomPart}`
}

function buildProductId(_name: string) {
  return buildOpaqueCatalogId('PRD')
}

function buildTechnicalSheetProductId(_name: string, kind: TechnicalSheetKind = 'PREPARO') {
  const prefix = kind === 'VENDA' ? 'VEN' : kind === 'EXECUCAO' ? 'EXE' : 'PRE'
  return buildOpaqueCatalogId(prefix)
}

function buildServiceItemId(name: string, kind: ServiceItemKind) {
  const slug = name
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/[^A-Z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 16)

  const prefix = kind === 'UTENSILIO_ELETRONICO' ? 'UTE' : 'REC'
  return slug ? `${prefix}-${slug}` : `${prefix}-NOVO-ITEM`
}

function buildPackageInternalCode(sequence: number) {
  return `EMB-${String(sequence).padStart(3, '0')}`
}

function buildStockCenterCode(sequence: number) {
  return `CEN-${String(sequence).padStart(3, '0')}`
}

function extractStockCenterCodeSequence(code: string) {
  const match = normalizeRegistrationText(code).match(/^CEN-(\d+)$/)
  if (!match) {
    return null
  }

  return Number.parseInt(match[1], 10)
}

function getTodayDateInputValue() {
  const today = new Date()
  const offset = today.getTimezoneOffset()
  return new Date(today.getTime() - offset * 60_000).toISOString().slice(0, 10)
}

function calculatePackagingWeight(
  packageForm: PackageForm,
  controlUnit: ControlUnit,
  densityFactor: number,
) {
  const packageQuantity = calculateNormalizedPackageQuantity(packageForm, controlUnit)
  const grossWeight = resolvePackageGrossWeight(packageForm, controlUnit)

  if (!packageQuantity || packageQuantity <= 0 || !grossWeight || grossWeight <= 0) {
    return null
  }

  let contentWeight = packageQuantity

  if (controlUnit === 'MILLILITER') {
    contentWeight = packageQuantity * densityFactor
  }

  return Math.max(grossWeight - contentWeight, 0)
}

function resolvePackageGrossWeight(packageForm: PackageForm, controlUnit: ControlUnit) {
  const informedGrossWeight = parseDecimal(packageForm.grossWeightGrams)
  if (informedGrossWeight && informedGrossWeight > 0) {
    return informedGrossWeight
  }

  const normalizedQuantity = calculateNormalizedPackageQuantity(packageForm, controlUnit)
  return normalizedQuantity > 0 ? normalizedQuantity : null
}

function resolveTechnicalSheetPackageGrossWeight(
  packageForm: PackageForm,
  controlUnit: ControlUnit,
  densityFactor: number,
) {
  const normalizedQuantity = calculateNormalizedPackageQuantity(packageForm, controlUnit)
  const packagingWeight = parseDecimal(packageForm.packagingWeightGrams) ?? 0

  if (normalizedQuantity <= 0) {
    return null
  }

  const contentWeight =
    controlUnit === 'MILLILITER' ? normalizedQuantity * densityFactor : normalizedQuantity

  return contentWeight + Math.max(packagingWeight, 0)
}

function resolveSectorDeletion(
  sectors: string[],
  sectorToDelete: string,
  resolution: 'replace' | 'inactivate',
  replacementSector: string,
) {
  const remaining = sectors.filter((sector) => sector !== sectorToDelete)

  if (remaining.length > 0) {
    return remaining
  }

  if (resolution === 'replace' && replacementSector) {
    return [replacementSector]
  }

  return []
}

function calculateProductUnitCost(
  product: ProductRecord,
  technicalSheets: TechnicalSheetRecord[] = [],
  products: ProductRecord[] = [],
) {
  if (typeof product.technicalSheetId === 'number') {
    const linkedTechnicalSheet = technicalSheets.find((sheet) => sheet.id === product.technicalSheetId) ?? null
    if (linkedTechnicalSheet) {
      const totalCost = calculateTechnicalSheetCost(linkedTechnicalSheet, technicalSheets, products)
      const totalYield = parseDecimal(linkedTechnicalSheet.outputQuantity) ?? 0
      return totalYield > 0 ? totalCost / totalYield : totalCost
    }
  }

  return calculatePackageOnlyProductUnitCost(product)
}

function calculatePackageOnlyProductUnitCost(product: ProductRecord) {
  const activePackages = product.packages.filter((item) => item.isActive)
  if (activePackages.length === 0) {
    return 0
  }

  const weightedPackages = activePackages
    .map((item) => {
      const quantity = calculateNormalizedPackageQuantity(item, product.controlUnit)
      const price = parseDecimal(item.purchasePrice) ?? 0
      const unitCost = quantity > 0 ? price / quantity : 0
      return {
        unitCost,
        weight: quantity,
      }
    })
    .filter((item) => item.unitCost > 0 && item.weight > 0)

  if (weightedPackages.length === 0) {
    const simpleAverage =
      activePackages
        .map((item) => {
          const quantity = calculateNormalizedPackageQuantity(item, product.controlUnit)
          const price = parseDecimal(item.purchasePrice) ?? 0
          return quantity > 0 ? price / quantity : 0
        })
        .filter((item) => item > 0)
    return simpleAverage.length > 0
      ? simpleAverage.reduce((sum, item) => sum + item, 0) / simpleAverage.length
      : 0
  }

  const totalWeight = weightedPackages.reduce((sum, item) => sum + item.weight, 0)
  if (totalWeight <= 0) {
    return 0
  }

  return weightedPackages.reduce((sum, item) => sum + item.unitCost * item.weight, 0) / totalWeight
}

function calculateTechnicalSheetCost(
  sheet: TechnicalSheetRecord,
  technicalSheets: TechnicalSheetRecord[],
  products: ProductRecord[] = [],
  visited = new Set<number>(),
): number {
  if (visited.has(sheet.id)) {
    return 0
  }

  const nextVisited = new Set(visited)
  nextVisited.add(sheet.id)

  return [...sheet.ingredients, ...sheet.garnishIngredients]
    .filter((ingredient) => ingredient.isActive)
    .reduce((sum, ingredient) => {
      const quantity = parseDecimal(ingredient.quantity) ?? 0
      const linkedTechnicalSheet =
        technicalSheets.find((item) => item.productId === ingredient.productId && item.companyId === sheet.companyId) ?? null

      if (linkedTechnicalSheet) {
      const linkedCost: number = calculateTechnicalSheetCost(linkedTechnicalSheet, technicalSheets, products, nextVisited)
      const linkedYield = calculateTechnicalSheetEffectiveYield(linkedTechnicalSheet)
      const linkedUnitCost: number = linkedYield > 0 ? linkedCost / linkedYield : linkedCost
      return sum + linkedUnitCost * quantity
      }

      const linkedProduct = products.find((item) => item.id === ingredient.productId) ?? null
      const linkedProductUnitCost = linkedProduct ? calculatePackageOnlyProductUnitCost(linkedProduct) : 0
      return sum + linkedProductUnitCost * quantity
    }, 0)
}

function calculateTechnicalSheetAlcoholPercentage(
  sheet: TechnicalSheetRecord,
  technicalSheets: TechnicalSheetRecord[],
  products: ProductRecord[] = [],
  visited = new Set<number>(),
): number {
  if (visited.has(sheet.id)) {
    return 0
  }

  const totalMixtureVolume = calculateTechnicalSheetAlcoholReferenceYield(sheet)
  if (totalMixtureVolume <= 0) {
    return 0
  }

  const nextVisited = new Set(visited)
  nextVisited.add(sheet.id)
  const referenceYield = calculateTechnicalSheetIngredientYieldSum(sheet, {
    includeGarnishes: sheet.kind !== 'EXECUCAO',
  })
  const finalYieldScaleFactor = referenceYield > 0 ? totalMixtureVolume / referenceYield : 1

  const alcoholSourceIngredients =
    sheet.kind === 'EXECUCAO' ? sheet.ingredients : [...sheet.ingredients, ...sheet.garnishIngredients]

  const totalAlcoholLoad = alcoholSourceIngredients
    .filter((ingredient) => ingredient.isActive)
    .reduce((sum, ingredient) => {
      const yieldQuantity = parseDecimal(ingredient.yieldQuantity) ?? 0
      if (yieldQuantity <= 0) {
        return sum
      }

      const linkedTechnicalSheet = technicalSheets.find((item) => item.productId === ingredient.productId) ?? null
      if (linkedTechnicalSheet) {
        return (
          sum +
          yieldQuantity *
            finalYieldScaleFactor *
            (calculateTechnicalSheetAlcoholPercentage(linkedTechnicalSheet, technicalSheets, products, nextVisited) / 100)
        )
      }

      const linkedProduct = products.find((item) => item.id === ingredient.productId) ?? null
      const alcoholPercentage = parseDecimal(linkedProduct?.alcoholPercentage ?? '') ?? 0
      const pureAlcoholVolume = yieldQuantity * finalYieldScaleFactor * (alcoholPercentage / 100)
      return sum + pureAlcoholVolume
    }, 0)

  return (totalAlcoholLoad / totalMixtureVolume) * 100
}

function calculateTechnicalSheetIngredientYieldSum(
  sheet: TechnicalSheetRecord,
  options: {
    includeGarnishes?: boolean
  } = {},
) {
  const { includeGarnishes = true } = options
  const sourceIngredients = includeGarnishes ? [...sheet.ingredients, ...sheet.garnishIngredients] : sheet.ingredients
  const ingredientYield = sourceIngredients
    .filter((ingredient) => ingredient.isActive)
    .reduce((sum, ingredient) => sum + (parseDecimal(ingredient.yieldQuantity) ?? 0), 0)

  return ingredientYield
}

function calculateTechnicalSheetEffectiveYield(sheet: TechnicalSheetRecord) {
  const includeGarnishesInYield = sheet.kind !== 'EXECUCAO'

  if (sheet.kind === 'EXECUCAO') {
    const savedYield = parseDecimal(sheet.outputQuantity) ?? 0
    if (savedYield > 0) {
      return savedYield
    }

    const ingredientYield = calculateTechnicalSheetIngredientYieldSum(sheet, {
      includeGarnishes: includeGarnishesInYield,
    })

    return ingredientYield
  }

  if (sheet.kind === 'PREPARO') {
    const savedYield = parseDecimal(sheet.outputQuantity) ?? 0
    if (savedYield > 0) {
      return savedYield
    }
  }

  if (sheet.kind === 'VENDA') {
    if (sheet.outputUnit === 'COMBO') {
      const comboUnits = (includeGarnishesInYield ? [...sheet.ingredients, ...sheet.garnishIngredients] : sheet.ingredients)
        .filter((ingredient) => ingredient.isActive)
        .reduce((sum, ingredient) => sum + (parseDecimal(ingredient.yieldQuantity) ?? parseDecimal(ingredient.quantity) ?? 0), 0)

      if (comboUnits > 0) {
        return comboUnits
      }
    }

    const ingredientYield = calculateTechnicalSheetIngredientYieldSum(sheet, {
      includeGarnishes: includeGarnishesInYield,
    })
    if (ingredientYield > 0) {
      return ingredientYield
    }

    return parseDecimal(sheet.outputQuantity) ?? 0
  }

  const ingredientYield = calculateTechnicalSheetIngredientYieldSum(sheet, {
    includeGarnishes: includeGarnishesInYield,
  })

  if (ingredientYield > 0) {
    return ingredientYield
  }

  return parseDecimal(sheet.outputQuantity) ?? 0
}

function getTechnicalSheetBaseYield(sheet: TechnicalSheetRecord) {
  const parsed = calculateTechnicalSheetEffectiveYield(sheet)
  return parsed > 0 ? parsed : 1
}

function getStockCenterBaseQuantity(sheet: TechnicalSheetRecord) {
  const portionBase = parseDecimal(sheet.portionSize) ?? 0
  return portionBase > 0 ? portionBase : getTechnicalSheetBaseYield(sheet)
}

function getInventoryClosedItemReferenceQuantity(sheet: TechnicalSheetRecord, hasRecipientOptions: boolean) {
  if (hasRecipientOptions) {
    return getStockCenterBaseQuantity(sheet)
  }

  const portionBase = parseDecimal(sheet.portionSize) ?? 0
  return portionBase > 0 ? portionBase : getStockCenterBaseQuantity(sheet)
}

function getInventoryClosedItemReferenceUnit(sheet: TechnicalSheetRecord, hasRecipientOptions: boolean): ControlUnit {
  if (hasRecipientOptions) {
    return sheet.kind === 'VENDA' ? 'UNIT' : sheet.outputUnit
  }

  return sheet.kind === 'VENDA' ? 'UNIT' : sheet.outputUnit
}

function calculateTechnicalSheetAlcoholReferenceYield(sheet: TechnicalSheetRecord) {
  return calculateTechnicalSheetEffectiveYield(sheet)
}

function inferTechnicalSheetMixtureControlUnit(
  sheet: TechnicalSheetRecord,
  technicalSheets: TechnicalSheetRecord[],
  products: ProductRecord[],
): ControlUnit | null {
  const units = [...sheet.ingredients, ...sheet.garnishIngredients]
    .filter((ingredient) => ingredient.isActive && ingredient.productId.trim() !== '')
    .map((ingredient) => {
      const linkedProduct = products.find((item) => item.id === ingredient.productId && item.companyId === sheet.companyId) ?? null
      if (linkedProduct) {
        return linkedProduct.controlUnit
      }

      const linkedTechnicalSheet =
        technicalSheets.find((item) => item.productId === ingredient.productId && item.companyId === sheet.companyId) ?? null
      return linkedTechnicalSheet?.outputUnit ?? null
    })
    .filter((unit): unit is ControlUnit => unit === 'MILLILITER' || unit === 'GRAM')

  const uniqueUnits = Array.from(new Set(units))
  if (uniqueUnits.length === 1) {
    return uniqueUnits[0]
  }

  return null
}

function getTechnicalSheetYieldUnitLabel(
  sheet: TechnicalSheetRecord,
  technicalSheets: TechnicalSheetRecord[],
  products: ProductRecord[],
) {
  if (sheet.kind === 'VENDA') {
    if (sheet.outputUnit === 'COMBO') {
      return 'UN'
    }

    if (sheet.outputUnit === 'UNIT') {
      const inferredUnit = inferTechnicalSheetMixtureControlUnit(sheet, technicalSheets, products)
      if (inferredUnit) {
        return formatControlUnitShort(inferredUnit)
      }

      return 'ML/G'
    }
  }

  if (sheet.kind === 'EXECUCAO') {
    const inferredUnit = inferTechnicalSheetMixtureControlUnit(sheet, technicalSheets, products)
    if (inferredUnit) {
      return formatControlUnitShort(inferredUnit)
    }

    return 'ML/G'
  }

  return formatControlUnitShort(sheet.outputUnit)
}

function calculateNormalizedPackageQuantity(packageForm: PackageForm, controlUnit: ControlUnit) {
  const quantity = parseDecimal(packageForm.packageQuantity) ?? 0
  if (quantity <= 0) {
    return 0
  }

  if (controlUnit === 'UNIT' || controlUnit === 'COMBO') {
    return quantity
  }

  if (controlUnit === 'MILLILITER') {
    return packageForm.packageUnit === 'LITER' ? quantity * 1000 : quantity
  }

  return packageForm.packageUnit === 'KILOGRAM' ? quantity * 1000 : quantity
}

function formatMoney(value: number) {
  return value.toLocaleString('pt-BR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })
}

function formatCurrencyLabel(value: number) {
  return `R$ ${formatMoney(value)}`
}

function formatControlUnitShort(unit: ControlUnit) {
  if (unit === 'MILLILITER') return 'ML'
  if (unit === 'GRAM') return 'G'
  if (unit === 'UNIT') return 'UN'
  return 'COMBO'
}

function parseDecimal(value: string) {
  const compact = value.replace(/\s/g, '')
  let normalized = compact

  if (compact.includes(',') && compact.includes('.')) {
    normalized = compact.replace(/\./g, '').replace(',', '.')
  } else if (compact.includes(',')) {
    normalized = compact.replace(',', '.')
  } else if (/^\d{1,3}(\.\d{3})+$/.test(compact)) {
    normalized = compact.replace(/\./g, '')
  }

  const parsed = Number(normalized)
  return Number.isFinite(parsed) ? parsed : null
}

function formatDecimal(value: number) {
  return value.toLocaleString('pt-BR', {
    minimumFractionDigits: value % 1 === 0 ? 0 : 2,
    maximumFractionDigits: 2,
  })
}

function formatUnit(unit: PackageUnit) {
  switch (unit) {
    case 'LITER':
      return 'L'
    case 'MILLILITER':
      return 'ml'
    case 'KILOGRAM':
      return 'kg'
    case 'GRAM':
      return 'g'
    case 'UNIT':
      return 'un'
    default:
      return unit
  }
}
